import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  ComposedChart, 
  Bar,
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  ReferenceLine,
  ReferenceArea,
  Cell,
  Scatter
} from 'recharts';
import { Card } from './Card';
import { TimeFrame } from '../types';
import { generateChartData } from '../constants';
import { Activity, Pencil, Square, Trash2, MousePointer2, Layers, PenTool, Undo2, TrendingUp } from 'lucide-react';

interface ChartWidgetProps {
  symbol: string;
}

interface Drawing {
  id: string;
  type: 'line' | 'box';
  startX: string; // Time label
  startY: number; // Price
  endX: string;
  endY: number;
}

type ToolType = 'cursor' | 'line' | 'box';

interface Signal {
  time: string;
  price: number;
  type: 'BUY' | 'SELL';
  desc: string;
}

// --- Indicator Helpers ---
const calculateSMA = (data: any[], period: number) => {
  return data.map((item, index, arr) => {
    if (index < period - 1) return { ...item, [`sma${period}`]: null };
    const slice = arr.slice(index - period + 1, index + 1);
    const sum = slice.reduce((acc, curr) => acc + curr.close, 0);
    return { ...item, [`sma${period}`]: sum / period };
  });
};

const calculateEMA = (data: any[], period: number) => {
  const k = 2 / (period + 1);
  let ema = data[0].close;
  return data.map((item, index) => {
    if (index === 0) return { ...item, ema: item.close };
    ema = (item.close - ema) * k + ema;
    return { ...item, ema };
  });
};

const calculateRSI = (data: any[], period: number = 14) => {
  let gains = 0;
  let losses = 0;
  for (let i = 1; i <= period; i++) {
    const change = data[i].close - data[i - 1].close;
    if (change > 0) gains += change;
    else losses -= change;
  }
  let avgGain = gains / period;
  let avgLoss = losses / period;

  return data.map((item, index) => {
    if (index < period) return { ...item, rsi: null };
    if (index > period) {
      const change = item.close - data[index - 1].close;
      const gain = change > 0 ? change : 0;
      const loss = change < 0 ? -change : 0;
      avgGain = (avgGain * (period - 1) + gain) / period;
      avgLoss = (avgLoss * (period - 1) + loss) / period;
    }
    const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    const rsi = 100 - (100 / (1 + rs));
    return { ...item, rsi };
  });
};

const calculateMACD = (data: any[]) => {
  const ema12Data = calculateEMA(data, 12);
  const ema26Data = calculateEMA(data, 26);
  const macdData = data.map((item, i) => {
    const ema12 = ema12Data[i].ema;
    const ema26 = ema26Data[i].ema;
    return { ...item, macdLine: (ema12 && ema26) ? ema12 - ema26 : null };
  });
  const period = 9;
  const k = 2 / (period + 1);
  let signal = 0;
  let firstValidIndex = -1;
  return macdData.map((item, i) => {
    if (item.macdLine === null) return { ...item, macdSignal: null, macdHistogram: null };
    if (firstValidIndex === -1) {
      firstValidIndex = i;
      signal = item.macdLine;
      return { ...item, macdSignal: signal, macdHistogram: 0 };
    }
    signal = (item.macdLine - signal) * k + signal;
    return { ...item, macdSignal: signal, macdHistogram: item.macdLine - signal };
  });
};

const analyzeTrendSignals = (data: any[]): Signal[] => {
  const signals: Signal[] = [];
  // Ensure we have both SMAs calculated before calling this, 
  // or calculate them locally if they aren't on the object.
  // For this logic, we assume data has sma50 and sma200 properties.

  for (let i = 1; i < data.length; i++) {
    const prev = data[i-1];
    const curr = data[i];

    if (prev.sma50 && prev.sma200 && curr.sma50 && curr.sma200) {
      // Golden Cross: 50 crosses above 200
      if (prev.sma50 <= prev.sma200 && curr.sma50 > curr.sma200) {
        signals.push({
          time: curr.time,
          price: curr.low * 0.995, // Position slightly below candle
          type: 'BUY',
          desc: 'Golden Cross (50 > 200 SMA)'
        });
      }
      // Death Cross: 50 crosses below 200
      else if (prev.sma50 >= prev.sma200 && curr.sma50 < curr.sma200) {
        signals.push({
          time: curr.time,
          price: curr.high * 1.005, // Position slightly above candle
          type: 'SELL',
          desc: 'Death Cross (50 < 200 SMA)'
        });
      }
    }
  }
  return signals;
};

export const ChartWidget: React.FC<ChartWidgetProps> = ({ symbol }) => {
  // Data State
  const [rawData, setRawData] = useState<any[]>([]);
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.M5);

  // View State (Zoom/Pan)
  const [viewState, setViewState] = useState({ start: 0, end: 100 }); // Indices
  const MIN_ZOOM = 20; // Minimum candles visible
  const DEFAULT_ZOOM = 100;

  // UI State
  const [indicators, setIndicators] = useState({ sma: false, ema: false, rsi: false, macd: false, signals: false });
  const [showComparison, setShowComparison] = useState(false);
  const [showToolbar, setShowToolbar] = useState(false);

  // Drawing State
  const [tool, setTool] = useState<ToolType>('cursor');
  const [drawings, setDrawings] = useState<Drawing[]>([]);
  const [currentDrawing, setCurrentDrawing] = useState<Partial<Drawing> | null>(null);

  // Interaction State
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState<number | null>(null); // X Coordinate

  const chartRef = useRef<HTMLDivElement>(null);

  // Initialize Data
  useEffect(() => {
    const totalPoints = 500;
    const newData = generateChartData(totalPoints);
    setRawData(newData);
    setViewState({ start: totalPoints - DEFAULT_ZOOM, end: totalPoints });
    setDrawings([]);
    setCurrentDrawing(null);
  }, [symbol, timeframe]);

  // Process Indicators & Comparison
  const fullChartData = useMemo(() => {
    if (!rawData.length) return [];
    let processed = [...rawData];

    // Always calc SMA 50/200 for signal detection if 'signals' is on, 
    // or if standard SMA indicator is on (though standard might use 20)
    // Here we calculate specifically for the requested feature
    processed = calculateSMA(processed, 50);
    processed = calculateSMA(processed, 200);

    // Standard indicators
    if (indicators.sma) processed = calculateSMA(processed, 20); // Standard period 20 for UI toggle
    if (indicators.ema) processed = calculateEMA(processed, 20);
    if (indicators.rsi) processed = calculateRSI(processed, 14);
    if (indicators.macd) processed = calculateMACD(processed);

    // Inject Signals
    if (indicators.signals) {
      const signals = analyzeTrendSignals(processed);
      // Merge signals into data points for Scatter chart
      // Note: Recharts Scatter prefers a separate data array usually, 
      // but if we want it synchronized with the category axis easily, 
      // we can also map signals to specific data points. 
      // However, creating a separate array filtered by viewport is cleaner for Scatter.
    }

    return processed;
  }, [rawData, indicators]);

  // Slice Data for View Window
  const visibleData = useMemo(() => {
    return fullChartData.slice(Math.max(0, viewState.start), Math.min(fullChartData.length, viewState.end));
  }, [fullChartData, viewState]);

  // Generate Signal Data for the current view
  const visibleSignals = useMemo(() => {
    if (!indicators.signals) return [];
    return analyzeTrendSignals(visibleData);
  }, [visibleData, indicators.signals]);

  // Calculate Y-Domains
  const yDomain = useMemo(() => {
    if (!visibleData.length) return [0, 0];
    const highs = visibleData.map(d => d.high);
    const lows = visibleData.map(d => d.low);
    const min = Math.min(...lows);
    const max = Math.max(...highs);
    const padding = (max - min) * 0.1;
    return [min - padding, max + padding];
  }, [visibleData]);

  const compareDomain = useMemo(() => {
    if (!showComparison || !visibleData.length) return [0, 0];
    const prices = visibleData.map(d => d.comparePrice);
    const min = Math.min(...prices);
    const max = Math.max(...prices);
    const padding = (max - min) * 0.1;
    return [min - padding, max + padding];
  }, [visibleData, showComparison]);

  // --- Zoom & Pan Handlers ---

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    if (tool !== 'cursor') return;

    const zoomSpeed = 0.5; // Adjust sensitivity
    const delta = Math.sign(e.deltaY) * Math.round(Math.abs(e.deltaY) * zoomSpeed);

    // Zoom centered on view (approximate)
    setViewState(prev => {
      const currentLength = prev.end - prev.start;
      let newLength = currentLength + delta;

      // Clamp zoom
      if (newLength < MIN_ZOOM) newLength = MIN_ZOOM;
      if (newLength > fullChartData.length) newLength = fullChartData.length;

      const center = prev.start + currentLength / 2;
      let newStart = center - newLength / 2;
      let newEnd = center + newLength / 2;

      // Boundary checks
      if (newEnd > fullChartData.length) {
        newEnd = fullChartData.length;
        newStart = newEnd - newLength;
      }
      if (newStart < 0) {
        newStart = 0;
        newEnd = newLength;
      }

      return { start: Math.round(newStart), end: Math.round(newEnd) };
    });
  };

  const getPriceFromY = (chartY: number, height: number) => {
    const [min, max] = yDomain;
    if (min === max) return min;

    // Adjust for chart margins defined in ComposedChart
    // margin={{ top: 20, right: 60, left: 10, bottom: 5 }}
    const top = 20;
    const bottom = 5;
    const chartHeight = height - top - bottom;

    if (chartHeight <= 0) return 0;

    // Relative Y from top of chart area
    const relativeY = chartY - top;

    // Calculate price ratio
    // y = 0 -> max price
    // y = height -> min price
    const ratio = Math.max(0, Math.min(1, relativeY / chartHeight));
    const priceRange = max - min;

    return max - (ratio * priceRange);
  };

  // Mouse Down: Start Draw or Pan
  const handleMouseDown = (e: any) => {
    if (!e) return;

    // Panning Logic
    if (tool === 'cursor') {
       setIsDragging(true);
       setDragStart(e.chartX);
       return;
    }

    // Drawing Logic
    if (e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing({
        id: Date.now().toString(),
        type: tool === 'line' ? 'line' : 'box',
        startX: e.activeLabel,
        startY: price,
        endX: e.activeLabel,
        endY: price
      });
    }
  };

  // Mouse Move: Update Draw or Pan
  const handleMouseMove = (e: any) => {
    if (!e) return;

    // Pan
    if (isDragging && tool === 'cursor' && dragStart !== null && e.chartX) {
       const deltaPixels = dragStart - e.chartX;
       const chartWidth = chartRef.current?.clientWidth || 800;
       const barWidth = chartWidth / visibleData.length;
       const deltaBars = Math.round(deltaPixels / barWidth);

       if (deltaBars !== 0) {
         setViewState(prev => {
            let newStart = prev.start + deltaBars;
            let newEnd = prev.end + deltaBars;

            // Bounds
            if (newStart < 0) { newStart = 0; newEnd = prev.end - prev.start; }
            if (newEnd > fullChartData.length) { newEnd = fullChartData.length; newStart = newEnd - (prev.end - prev.start); }

            return { start: newStart, end: newEnd };
         });
         setDragStart(e.chartX); // Reset anchor to prevent acceleration
       }
       return;
    }

    // Draw
    if (currentDrawing && e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing(prev => ({
        ...prev,
        endX: e.activeLabel,
        endY: price
      }));
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
    setDragStart(null);
    if (currentDrawing && currentDrawing.endX && currentDrawing.endY) {
      setDrawings(prev => [...prev, currentDrawing as Drawing]);
      setCurrentDrawing(null);
      // Don't reset tool to cursor, allows continuous drawing
    }
  };

  const toggleIndicator = (key: keyof typeof indicators) => {
    setIndicators(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleUndo = () => {
    setDrawings(prev => prev.slice(0, -1));
  };

  // Custom Tooltip
  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      // Check if we are hovering over a scatter point (Signal)
      const signalPayload = payload.find((p: any) => p.dataKey === 'price' && p.payload.type);
      if (signalPayload) {
        const { type, desc, price } = signalPayload.payload;
        return (
          <div className={`bg-terminal-panel border ${type === 'BUY' ? 'border-terminal-up' : 'border-terminal-down'} p-2 rounded shadow-xl text-xs font-mono z-50`}>
            <div className={`font-bold ${type === 'BUY' ? 'text-terminal-up' : 'text-terminal-down'} mb-1`}>
              {type} SIGNAL
            </div>
            <div className="text-white mb-1">{desc}</div>
            <div className="text-gray-400">Trigger Price: <span className="text-white">{price.toFixed(2)}</span></div>
            <div className="text-gray-400">Time: <span className="text-white">{label}</span></div>
          </div>
        )
      }

      // Default Candle Tooltip
      const main = payload[0].payload;
      const priceChange = main.close - main.open;
      const isUp = priceChange >= 0;

      return (
        <div className="bg-terminal-panel/95 backdrop-blur border border-terminal-border p-3 rounded shadow-2xl text-xs font-mono z-50 min-w-[180px]">
          <div className="flex justify-between items-center mb-2 border-b border-terminal-border pb-1">
             <span className="text-terminal-muted">{label}</span>
             <span className={isUp ? 'text-terminal-up' : 'text-terminal-down'}>
               {isUp ? '▲' : '▼'} {Math.abs(priceChange).toFixed(2)}
             </span>
          </div>
          <div className="grid grid-cols-2 gap-x-4 gap-y-1">
            <span className="text-gray-500">Open:</span> <span className="text-right text-white">{main.open.toFixed(2)}</span>
            <span className="text-gray-500">High:</span> <span className="text-right text-white">{main.high.toFixed(2)}</span>
            <span className="text-gray-500">Low:</span> <span className="text-right text-white">{main.low.toFixed(2)}</span>
            <span className="text-gray-500">Close:</span> <span className="text-right text-white">{main.close.toFixed(2)}</span>
          </div>
          {indicators.signals && (
            <div className="mt-2 pt-2 border-t border-terminal-border text-[10px] text-gray-500">
               SMA50: <span className="text-blue-400">{main.sma50?.toFixed(2) || 'N/A'}</span> <br/>
               SMA200: <span className="text-purple-400">{main.sma200?.toFixed(2) || 'N/A'}</span>
            </div>
          )}
        </div>
      );
    }
    return null;
  };

  // Signal Marker Shapes
  const RenderSignalShape = (props: any) => {
    const { cx, cy, payload } = props;
    if (payload.type === 'BUY') {
      return (
        <svg x={cx - 6} y={cy - 6} width={12} height={12} viewBox="0 0 24 24" fill="#00ff41" stroke="#00ff41" strokeWidth="2">
          <path d="M12 2L2 22h20L12 2z" />
        </svg>
      );
    }
    return (
      <svg x={cx - 6} y={cy - 6} width={12} height={12} viewBox="0 0 24 24" fill="#ff1a1a" stroke="#ff1a1a" strokeWidth="2">
         <path d="M12 22L22 2H2L12 22z" />
      </svg>
    );
  };

  return (
    <Card 
      title={`Price Action - ${symbol}`} 
      className="h-full flex flex-col relative group"
      actions={
        <div className="flex items-center space-x-3">
          {/* Timeframe Selectors */}
           <div className="flex items-center border border-terminal-border rounded overflow-hidden">
              {[TimeFrame.M1, TimeFrame.M5, TimeFrame.H1, TimeFrame.D1].map((tf) => (
                <button
                  key={tf}
                  onClick={() => setTimeframe(tf)}
                  className={`px-2 py-0.5 text-[10px] font-mono transition-colors ${timeframe === tf ? 'bg-terminal-accent text-black font-bold' : 'bg-[#111] text-gray-500 hover:text-white'}`}
                >
                  {tf}
                </button>
              ))}
           </div>

           <div className="h-4 w-px bg-terminal-border"></div>

           {/* Toolbar Toggle */}
           <button 
             onClick={() => setShowToolbar(!showToolbar)}
             className={`p-1 rounded transition-colors ${showToolbar ? 'text-terminal-accent bg-white/10' : 'text-gray-500 hover:text-white'}`}
             title="Toggle Drawing Tools"
           >
             <PenTool size={14} />
           </button>

           {/* Comparison Toggle */}
           <button 
             onClick={() => setShowComparison(!showComparison)}
             className={`p-1 rounded transition-colors ${showComparison ? 'text-yellow-400 bg-yellow-400/10' : 'text-gray-500 hover:text-white'}`}
             title="Compare with Market"
           >
             <Layers size={14} />
           </button>

           {/* Indicators */}
           <div className="hidden xl:flex items-center space-x-1">
             <Activity size={12} className="text-gray-500 mr-1" />
             {(['sma', 'ema', 'rsi', 'macd', 'signals'] as const).map((ind) => (
               <button
                 key={ind}
                 onClick={() => toggleIndicator(ind)}
                 className={`px-1.5 py-0.5 text-[10px] rounded uppercase font-mono transition-all ${
                   indicators[ind] 
                     ? 'bg-terminal-accent/20 text-terminal-accent border border-terminal-accent/30' 
                     : 'text-gray-500 hover:text-white hover:bg-white/5'
                 }`}
               >
                 {ind}
               </button>
             ))}
          </div>
        </div>
      }
    >
      <div className="flex flex-col h-full bg-[#050505] relative select-none">

        {/* Visible Sidebar Toolbar */}
        {showToolbar && (
          <div className="absolute left-2 top-2 z-20 flex flex-col gap-1 bg-terminal-panel border border-terminal-border rounded shadow-xl p-1 animate-in slide-in-from-left-2 duration-200">
             <button title="Cursor (Pan/Zoom)" onClick={() => setTool('cursor')} className={`p-2 rounded ${tool === 'cursor' ? 'bg-terminal-accent text-black' : 'text-gray-400 hover:bg-white/10'}`}><MousePointer2 size={16} /></button>
             <button title="Trendline" onClick={() => setTool('line')} className={`p-2 rounded ${tool === 'line' ? 'bg-terminal-accent text-black' : 'text-gray-400 hover:bg-white/10'}`}><Pencil size={16} /></button>
             <button title="Box / Zone" onClick={() => setTool('box')} className={`p-2 rounded ${tool === 'box' ? 'bg-terminal-accent text-black' : 'text-gray-400 hover:bg-white/10'}`}><Square size={16} /></button>
             <div className="h-px bg-terminal-border my-1"></div>
             <button title="Undo Last" onClick={handleUndo} className="p-2 rounded text-gray-400 hover:text-white hover:bg-white/10"><Undo2 size={16} /></button>
             <button title="Clear All" onClick={() => setDrawings([])} className="p-2 rounded text-red-400 hover:bg-red-500/20"><Trash2 size={16} /></button>
          </div>
        )}

        {/* Overlay Info */}
        <div className="absolute top-4 left-14 z-10 flex flex-col pointer-events-none">
          <div className="flex items-baseline space-x-2">
            <h2 className="text-3xl font-bold text-white font-mono tracking-tighter">{symbol}</h2>
            <span className="text-lg font-medium text-gray-400">{timeframe}</span>
          </div>
          {visibleData.length > 0 && (
            <div className={`flex items-center space-x-2 text-sm font-mono mt-1 ${visibleData[visibleData.length-1].close >= visibleData[visibleData.length-1].open ? 'text-terminal-up' : 'text-terminal-down'}`}>
               <span className="font-bold">{visibleData[visibleData.length-1].close.toFixed(2)}</span>
               <span>{visibleData[visibleData.length-1].close >= visibleData[visibleData.length-1].open ? '+' : ''}{(visibleData[visibleData.length-1].close - visibleData[visibleData.length-1].open).toFixed(2)}</span>
            </div>
          )}
        </div>

        {/* Main Chart Area */}
        <div className="flex-1 min-h-0 relative" ref={chartRef} onWheel={handleWheel}>
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart 
              data={visibleData} 
              margin={{ top: 20, right: 60, left: 10, bottom: 5 }}
              onMouseDown={handleMouseDown}
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              onMouseLeave={handleMouseUp}
              style={{ cursor: tool === 'cursor' ? (isDragging ? 'grabbing' : 'grab') : 'crosshair' }}
            >
              <defs>
                <linearGradient id="volGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#333" stopOpacity={0.8}/>
                  <stop offset="95%" stopColor="#333" stopOpacity={0.1}/>
                </linearGradient>
              </defs>

              <CartesianGrid stroke="#1a1a1a" strokeDasharray="3 3" vertical={true} horizontal={true} />

              <XAxis 
                dataKey="time" 
                tick={{ fontSize: 10, fill: '#555', fontFamily: 'JetBrains Mono' }} 
                axisLine={{ stroke: '#333' }}
                tickLine={false}
                minTickGap={50}
                allowDuplicatedCategory={false}
                interval="preserveStartEnd"
              />

              {/* Main Price Axis */}
              <YAxis 
                yAxisId="price"
                domain={yDomain} 
                orientation="right" 
                tick={{ fontSize: 10, fill: '#aaa', fontFamily: 'JetBrains Mono' }} 
                axisLine={false}
                tickLine={{ stroke: '#333' }}
                tickFormatter={(val) => val.toFixed(2)}
                width={50}
                mirror={false}
              />

              {/* Volume Axis (Hidden) */}
              <YAxis yAxisId="volume" orientation="left" domain={[0, 'dataMax * 4']} hide />

              {/* Comparison Axis */}
              {showComparison && (
                 <YAxis yAxisId="compare" domain={compareDomain} orientation="left" hide={true} />
              )}

              <Tooltip 
                 content={<CustomTooltip />} 
                 cursor={{ stroke: '#ffffff', strokeWidth: 1, strokeDasharray: '4 4', opacity: 0.5 }}
                 isAnimationActive={false}
              />

              {/* Volume Bars */}
              <Bar dataKey="volume" yAxisId="volume" fill="url(#volGradient)" barSize={5} isAnimationActive={false} />

              {/* Candlesticks: Wicks */}
              <Bar 
                 dataKey={(d) => [d.low, d.high]} 
                 yAxisId="price"
                 barSize={1} 
                 fill="#fff" 
                 isAnimationActive={false}
              >
                 {visibleData.map((entry, index) => (
                    <Cell key={`wick-${index}`} fill={entry.close >= entry.open ? '#00ff41' : '#ff1a1a'} />
                 ))}
              </Bar>

              {/* Candlesticks: Bodies */}
              <Bar 
                 dataKey={(d) => [Math.min(d.open, d.close), Math.max(d.open, d.close)]}
                 yAxisId="price"
                 barSize={8}
                 isAnimationActive={false}
              >
                 {visibleData.map((entry, index) => (
                    <Cell key={`body-${index}`} fill={entry.close >= entry.open ? '#00ff41' : '#ff1a1a'} />
                 ))}
              </Bar>

              {/* Comparison Line */}
              {showComparison && (
                 <Line 
                   yAxisId="compare"
                   type="monotone" 
                   dataKey="comparePrice" 
                   stroke="#facc15" 
                   strokeWidth={2} 
                   dot={false}
                   isAnimationActive={false}
                 />
              )}

              {/* Standard Indicators */}
              {indicators.sma && <Line yAxisId="price" type="monotone" dataKey="sma20" stroke="#fb923c" strokeWidth={1} dot={false} isAnimationActive={false} />}
              {indicators.ema && <Line yAxisId="price" type="monotone" dataKey="ema" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />}

              {/* Signals Visualization (Scatter) */}
              {indicators.signals && (
                <>
                  <Line yAxisId="price" type="monotone" dataKey="sma50" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} strokeOpacity={0.6} />
                  <Line yAxisId="price" type="monotone" dataKey="sma200" stroke="#a855f7" strokeWidth={1} dot={false} isAnimationActive={false} strokeOpacity={0.6} />
                  <Scatter 
                    yAxisId="price" 
                    data={visibleSignals} 
                    shape={<RenderSignalShape />} 
                    isAnimationActive={false}
                  />
                </>
              )}

              {/* Drawings */}
              {drawings.map((d) => (
                d.type === 'line' 
                  ? <ReferenceLine yAxisId="price" key={d.id} segment={[{ x: d.startX, y: d.startY }, { x: d.endX, y: d.endY }]} stroke="#eab308" strokeWidth={2} />
                  : <ReferenceArea yAxisId="price" key={d.id} x1={d.startX} x2={d.endX} y1={d.startY} y2={d.endY} fill="#eab308" fillOpacity={0.2} stroke="#eab308" />
              ))}

              {/* Current Drawing Preview */}
              {currentDrawing && currentDrawing.endX && (
                 currentDrawing.type === 'line'
                 ? <ReferenceLine yAxisId="price" segment={[{ x: currentDrawing.startX!, y: currentDrawing.startY! }, { x: currentDrawing.endX, y: currentDrawing.endY }]} stroke="#eab308" strokeWidth={2} strokeDasharray="3 3" />
                 : <ReferenceArea yAxisId="price" x1={currentDrawing.startX} x2={currentDrawing.endX} y1={currentDrawing.startY} y2={currentDrawing.endY} fill="#eab308" fillOpacity={0.1} stroke="#eab308" strokeDasharray="3 3" />
              )}
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {/* RSI Indicator Panel */}
        {indicators.rsi && (
          <div className="h-24 shrink-0 border-t border-terminal-border/50 bg-[#0a0a0a]">
             <ResponsiveContainer width="100%" height="100%">
               <ComposedChart data={visibleData} margin={{ top: 5, right: 60, left: 10, bottom: 0 }}>
                 <CartesianGrid stroke="#222" strokeDasharray="3 3" vertical={false} />
                 <YAxis domain={[0, 100]} orientation="right" tick={{ fontSize: 9, fill: '#666' }} axisLine={false} tickLine={false} width={50} ticks={[30, 70]} />
                 <Tooltip content={<CustomTooltip />} cursor={{ stroke: '#444', strokeDasharray: '4 4' }} />
                 <ReferenceLine y={70} stroke="#444" strokeDasharray="3 3" />
                 <ReferenceLine y={30} stroke="#444" strokeDasharray="3 3" />
                 <Line type="monotone" dataKey="rsi" stroke="#c084fc" strokeWidth={1} dot={false} isAnimationActive={false} />
               </ComposedChart>
             </ResponsiveContainer>
          </div>
        )}

        {/* MACD Indicator Panel */}
        {indicators.macd && (
          <div className="h-24 shrink-0 border-t border-terminal-border/50 bg-[#0a0a0a]">
             <ResponsiveContainer width="100%" height="100%">
               <ComposedChart data={visibleData} margin={{ top: 5, right: 60, left: 10, bottom: 0 }}>
                 <CartesianGrid stroke="#222" strokeDasharray="3 3" vertical={false} />
                 <YAxis orientation="right" tick={{ fontSize: 9, fill: '#666' }} axisLine={false} tickLine={false} width={50} />
                 <Tooltip content={<CustomTooltip />} cursor={{ stroke: '#444', strokeDasharray: '4 4' }} />
                 <ReferenceLine y={0} stroke="#444" />
                 <Bar dataKey="macdHistogram" fill="#444" isAnimationActive={false}>
                    {visibleData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={(entry as any).macdHistogram > 0 ? '#22c55e' : '#ef4444'} />
                    ))}
                 </Bar>
                 <Line type="monotone" dataKey="macdLine" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />
                 <Line type="monotone" dataKey="macdSignal" stroke="#f97316" strokeWidth={1} dot={false} isAnimationActive={false} />
               </ComposedChart>
             </ResponsiveContainer>
          </div>
        )}
      </div>
    </Card>
  );
};

