import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  ComposedChart, 
  Bar,
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  ReferenceLine,
  ReferenceArea,
  Cell,
  Scatter,
  Brush
} from 'recharts';
import { Card } from './Card';
import { TimeFrame } from '../types';
import { generateChartData } from '../constants';
import { Activity, Pencil, Square, Trash2, MousePointer2, Layers, PenTool, Undo2 } from 'lucide-react';

interface ChartWidgetProps {
  symbol: string;
}

interface Drawing {
  id: string;
  type: 'line' | 'box';
  startX: string; // Time label
  startY: number; // Price
  endX: string;
  endY: number;
}

type ToolType = 'cursor' | 'line' | 'box';

interface Signal {
  time: string;
  price: number;
  type: 'BUY' | 'SELL';
  desc: string;
}

// --- Indicator Helpers ---
const calculateSMA = (data: any[], period: number) => {
  return data.map((item, index, arr) => {
    if (index < period - 1) return { ...item, [`sma${period}`]: null };
    const slice = arr.slice(index - period + 1, index + 1);
    const sum = slice.reduce((acc, curr) => acc + curr.close, 0);
    return { ...item, [`sma${period}`]: sum / period };
  });
};

const calculateEMA = (data: any[], period: number) => {
  const k = 2 / (period + 1);
  let ema = data[0].close;
  return data.map((item, index) => {
    if (index === 0) return { ...item, ema: item.close };
    ema = (item.close - ema) * k + ema;
    return { ...item, ema };
  });
};

const calculateRSI = (data: any[], period: number = 14) => {
  let gains = 0;
  let losses = 0;
  for (let i = 1; i <= period; i++) {
    const change = data[i].close - data[i - 1].close;
    if (change > 0) gains += change;
    else losses -= change;
  }
  let avgGain = gains / period;
  let avgLoss = losses / period;

  return data.map((item, index) => {
    if (index < period) return { ...item, rsi: null };
    if (index > period) {
      const change = item.close - data[index - 1].close;
      const gain = change > 0 ? change : 0;
      const loss = change < 0 ? -change : 0;
      avgGain = (avgGain * (period - 1) + gain) / period;
      avgLoss = (avgLoss * (period - 1) + loss) / period;
    }
    const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    const rsi = 100 - (100 / (1 + rs));
    return { ...item, rsi };
  });
};

const calculateMACD = (data: any[]) => {
  const ema12Data = calculateEMA(data, 12);
  const ema26Data = calculateEMA(data, 26);
  const macdData = data.map((item, i) => {
    const ema12 = ema12Data[i].ema;
    const ema26 = ema26Data[i].ema;
    return { ...item, macdLine: (ema12 && ema26) ? ema12 - ema26 : null };
  });
  const period = 9;
  const k = 2 / (period + 1);
  let signal = 0;
  let firstValidIndex = -1;
  return macdData.map((item, i) => {
    if (item.macdLine === null) return { ...item, macdSignal: null, macdHistogram: null };
    if (firstValidIndex === -1) {
      firstValidIndex = i;
      signal = item.macdLine;
      return { ...item, macdSignal: signal, macdHistogram: 0 };
    }
    signal = (item.macdLine - signal) * k + signal;
    return { ...item, macdSignal: signal, macdHistogram: item.macdLine - signal };
  });
};

const analyzeTrendSignals = (data: any[]): Signal[] => {
  const signals: Signal[] = [];

  for (let i = 1; i < data.length; i++) {
    const prev = data[i-1];
    const curr = data[i];

    if (prev.sma50 && prev.sma200 && curr.sma50 && curr.sma200) {
      // Golden Cross: 50 crosses above 200
      if (prev.sma50 <= prev.sma200 && curr.sma50 > curr.sma200) {
        signals.push({
          time: curr.time,
          price: curr.low * 0.995, 
          type: 'BUY',
          desc: 'Golden Cross (50 > 200 SMA)'
        });
      }
      // Death Cross: 50 crosses below 200
      else if (prev.sma50 >= prev.sma200 && curr.sma50 < curr.sma200) {
        signals.push({
          time: curr.time,
          price: curr.high * 1.005, 
          type: 'SELL',
          desc: 'Death Cross (50 < 200 SMA)'
        });
      }
    }
  }
  return signals;
};

export const ChartWidget: React.FC<ChartWidgetProps> = ({ symbol }) => {
  // Data State
  const [rawData, setRawData] = useState<any[]>([]);
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.M5);

  // View State (Zoom/Pan) - Controlling Brush
  const [viewState, setViewState] = useState({ start: 0, end: 100 }); 
  const MIN_ZOOM = 20; 
  const DEFAULT_ZOOM = 100;

  // UI State
  const [indicators, setIndicators] = useState({ sma: false, ema: false, rsi: false, macd: false, signals: false });
  const [showComparison, setShowComparison] = useState(false);
  const [showToolbar, setShowToolbar] = useState(false);

  // Drawing State
  const [tool, setTool] = useState<ToolType>('cursor');
  const [drawings, setDrawings] = useState<Drawing[]>([]);
  const [currentDrawing, setCurrentDrawing] = useState<Partial<Drawing> | null>(null);

  // Interaction State
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState<number | null>(null); 

  const chartRef = useRef<HTMLDivElement>(null);

  // Initialize Data
  useEffect(() => {
    const totalPoints = 500;
    const newData = generateChartData(totalPoints);
    setRawData(newData);
    setViewState({ start: totalPoints - DEFAULT_ZOOM, end: totalPoints - 1 });
    setDrawings([]);
    setCurrentDrawing(null);
  }, [symbol, timeframe]);

  // Process Indicators & Comparison
  const fullChartData = useMemo(() => {
    if (!rawData.length) return [];
    let processed = [...rawData];

    processed = calculateSMA(processed, 50);
    processed = calculateSMA(processed, 200);

    if (indicators.sma) processed = calculateSMA(processed, 20);
    if (indicators.ema) processed = calculateEMA(processed, 20);
    if (indicators.rsi) processed = calculateRSI(processed, 14);
    if (indicators.macd) processed = calculateMACD(processed);

    return processed;
  }, [rawData, indicators]);

  // Generate Signal Data (on full dataset)
  const signalData = useMemo(() => {
    if (!indicators.signals) return [];
    return analyzeTrendSignals(fullChartData);
  }, [fullChartData, indicators.signals]);

  // Calculate Y-Domains based on *Visible* slice (controlled by viewState)
  // We need to slice manually just for domain calculation, even though we pass full data to chart
  const yDomain = useMemo(() => {
    if (!fullChartData.length) return [0, 0];
    const visibleSlice = fullChartData.slice(viewState.start, viewState.end + 1);
    if (!visibleSlice.length) return [0, 0];

    const highs = visibleSlice.map(d => d.high);
    const lows = visibleSlice.map(d => d.low);
    const min = Math.min(...lows);
    const max = Math.max(...highs);
    const padding = (max - min) * 0.1;
    return [min - padding, max + padding];
  }, [fullChartData, viewState]);

  const compareDomain = useMemo(() => {
    if (!showComparison || !fullChartData.length) return [0, 0];
    const visibleSlice = fullChartData.slice(viewState.start, viewState.end + 1);
    const prices = visibleSlice.map(d => d.comparePrice);
    const min = Math.min(...prices);
    const max = Math.max(...prices);
    const padding = (max - min) * 0.1;
    return [min - padding, max + padding];
  }, [fullChartData, showComparison, viewState]);

  // --- Zoom & Pan Handlers ---

  const handleBrushChange = (e: any) => {
    if (e.startIndex !== undefined && e.endIndex !== undefined) {
      setViewState({ start: e.startIndex, end: e.endIndex });
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    if (tool !== 'cursor') return;

    const zoomSpeed = 0.5;
    const delta = Math.sign(e.deltaY) * Math.round(Math.abs(e.deltaY) * zoomSpeed);

    setViewState(prev => {
      const currentLength = prev.end - prev.start;
      let newLength = currentLength + delta;

      if (newLength < MIN_ZOOM) newLength = MIN_ZOOM;
      if (newLength > fullChartData.length) newLength = fullChartData.length;

      const center = prev.start + currentLength / 2;
      let newStart = center - newLength / 2;
      let newEnd = center + newLength / 2;

      if (newEnd >= fullChartData.length) {
        newEnd = fullChartData.length - 1;
        newStart = newEnd - newLength;
      }
      if (newStart < 0) {
        newStart = 0;
        newEnd = newLength;
      }

      return { start: Math.round(newStart), end: Math.round(newEnd) };
    });
  };

  const getPriceFromY = (chartY: number, height: number) => {
    const [min, max] = yDomain;
    if (min === max) return min;
    const top = 20;
    const bottom = 40; // Adjusted for Brush height
    const chartHeight = height - top - bottom;
    if (chartHeight <= 0) return 0;
    const relativeY = chartY - top;
    const ratio = Math.max(0, Math.min(1, relativeY / chartHeight));
    const priceRange = max - min;
    return max - (ratio * priceRange);
  };

  const handleMouseDown = (e: any) => {
    if (!e) return;
    if (tool === 'cursor') {
       setIsDragging(true);
       setDragStart(e.chartX);
       return;
    }
    if (e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing({
        id: Date.now().toString(),
        type: tool === 'line' ? 'line' : 'box',
        startX: e.activeLabel,
        startY: price,
        endX: e.activeLabel,
        endY: price
      });
    }
  };

  const handleMouseMove = (e: any) => {
    if (!e) return;
    if (isDragging && tool === 'cursor' && dragStart !== null && e.chartX) {
       // Manual panning is tricky with Brush, rely on Brush panning or implement if needed.
       // Disabling manual pan via drag to avoid conflict with Brush state for now, 
       // as user requested "Date Range Slider" which implies Brush usage.
       return;
    }
    if (currentDrawing && e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing(prev => ({
        ...prev,
        endX: e.activeLabel,
        endY: price
      }));
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
    setDragStart(null);
    if (currentDrawing && currentDrawing.endX && currentDrawing.endY) {
      setDrawings(prev => [...prev, currentDrawing as Drawing]);
      setCurrentDrawing(null);
    }
  };

  const toggleIndicator = (key: keyof typeof indicators) => {
    setIndicators(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleUndo = () => {
    setDrawings(prev => prev.slice(0, -1));
  };

  // Custom Tooltip
  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const signalPayload = payload.find((p: any) => p.dataKey === 'price' && p.payload.type);
      if (signalPayload) {
        const { type, desc, price } = signalPayload.payload;
        return (
          <div className={`bg-terminal-panel border ${type === 'BUY' ? 'border-terminal-up' : 'border-terminal-down'} p-2 rounded shadow-xl text-xs font-mono z-50`}>
            <div className={`font-bold ${type === 'BUY' ? 'text-terminal-up' : 'text-terminal-down'} mb-1`}>
              {type} SIGNAL
            </div>
            <div className="text-white mb-1">{desc}</div>
            <div className="text-gray-400">Trigger Price: <span className="text-white">{price.toFixed(2)}</span></div>
            <div className="text-gray-400">Time: <span className="text-white">{label}</span></div>
          </div>
        )
      }

      const main = payload[0].payload;
      const priceChange = main.close - main.open;
      const isUp = priceChange >= 0;

      return (
        <div className="bg-terminal-panel/95 backdrop-blur border border-terminal-border p-3 rounded shadow-2xl text-xs font-mono z-50 min-w-[180px]">
          <div className="flex justify-between items-center mb-2 border-b border-terminal-border pb-1">
             <span className="text-terminal-muted">{label}</span>
             <span className={isUp ? 'text-[#228B22]' : 'text-[#B22222]'}>
               {isUp ? '▲' : '▼'} {Math.abs(priceChange).toFixed(2)}
             </span>
          </div>
          <div className="grid grid-cols-2 gap-x-4 gap-y-1">
            <span className="text-gray-500">Open:</span> <span className="text-right text-white">{main.open.toFixed(2)}</span>
            <span className="text-gray-500">High:</span> <span className="text-right text-white">{main.high.toFixed(2)}</span>
            <span className="text-gray-500">Low:</span> <span className="text-right text-white">{main.low.toFixed(2)}</span>
            <span className="text-gray-500">Close:</span> <span className="text-right text-white">{main.close.toFixed(2)}</span>
          </div>
          {indicators.signals && (
            <div className="mt-2 pt-2 border-t border-terminal-border text-[10px] text-gray-500">
               SMA50: <span className="text-blue-400">{main.sma50?.toFixed(2) || 'N/A'}</span> <br/>
               SMA200: <span className="text-purple-400">{main.sma200?.toFixed(2) || 'N/A'}</span>
            </div>
          )}
        </div>
      );
    }
    return null;
  };

  const RenderSignalShape = (props: any) => {
    const { cx, cy, payload } = props;
    if (payload.type === 'BUY') {
      return (
        <svg x={cx - 6} y={cy - 6} width={12} height={12} viewBox="0 0 24 24" fill="#228B22" stroke="#228B22" strokeWidth="2">
          <path d="M12 2L2 22h20L12 2z" />
        </svg>
      );
    }
    return (
      <svg x={cx - 6} y={cy - 6} width={12} height={12} viewBox="0 0 24 24" fill="#B22222" stroke="#B22222" strokeWidth="2">
         <path d="M12 22L22 2H2L12 22z" />
      </svg>
    );
  };

  return (
    <Card 
      title={`Price Action - ${symbol}`} 
      className="h-full flex flex-col relative group"
      actions={
        <div className="flex items-center space-x-3">
           <div className="flex items-center border border-terminal-border rounded overflow-hidden">
              {[TimeFrame.M1, TimeFrame.M5, TimeFrame.H1, TimeFrame.D1].map((tf) => (
                <button
                  key={tf}
                  onClick={() => setTimeframe(tf)}
                  className={`px-2 py-0.5 text-[10px] font-mono transition-colors ${timeframe === tf ? 'bg-terminal-accent text-black font-bold' : 'bg-[#111] text-gray-500 hover:text-white'}`}
                >
                  {tf}
                </button>
              ))}
           </div>
           <div className="h-4 w-px bg-terminal-border"></div>
           <button 
             onClick={() => setShowToolbar(!showToolbar)}
             className={`p-1 rounded transition-colors ${showToolbar ? 'text-terminal-accent bg-white/10' : 'text-gray-500 hover:text-white'}`}
             title="Toggle Drawing Tools"
           >
             <PenTool size={14} />
           </button>
           <button 
             onClick={() => setShowComparison(!showComparison)}
             className={`p-1 rounded transition-colors ${showComparison ? 'text-yellow-400 bg-yellow-400/10' : 'text-gray-500 hover:text-white'}`}
             title="Compare with Market"
           >
             <Layers size={14} />
           </button>
           <div className="hidden xl:flex items-center space-x-1">
             <Activity size={12} className="text-gray-500 mr-1" />
             {(['sma', 'ema', 'rsi', 'macd', 'signals'] as const).map((ind) => (
               <button
                 key={ind}
                 onClick={() => toggleIndicator(ind)}
                 className={`px-1.5 py-0.5 text-[10px] rounded uppercase font-mono transition-all ${
                   indicators[ind] 
                     ? 'bg-terminal-accent/20 text-terminal-accent border border-terminal-accent/30' 
                     : 'text-gray-500 hover:text-white hover:bg-white/5'
                 }`}
               >
                 {ind}
               </button>
             ))}
          </div>
        </div>
      }
    >
      <div className="flex flex-col h-full bg-[#050505] relative select-none">

        {showToolbar && (
          <div className="absolute left-2 top-2 z-20 flex flex-col gap-1 bg-terminal-panel border border-terminal-border rounded shadow-xl p-1 animate-in slide-in-from-left-2 duration-200">
             <button title="Cursor" onClick={() => setTool('cursor')} className={`p-2 rounded ${tool === 'cursor' ? 'bg-terminal-accent text-black' : 'text-gray-400 hover:bg-white/10'}`}><MousePointer2 size={16} /></button>
             <button title="Trendline" onClick={() => setTool('line')} className={`p-2 rounded ${tool === 'line' ? 'bg-terminal-accent text-black' : 'text-gray-400 hover:bg-white/10'}`}><Pencil size={16} /></button>
