             <button title="Clear All" onClick={() => setDrawings([])} className="p-2 rounded text-red-400 hover:bg-red-500/20"><Trash2 size={16} /></button>
          </div>
        )}

        <div className="absolute top-4 left-14 z-10 flex flex-col pointer-events-none">
          <div className="flex items-baseline space-x-2">
            <h2 className="text-3xl font-bold text-white font-mono tracking-tighter">{symbol}</h2>
            <span className="text-lg font-medium text-gray-400">{timeframe}</span>
          </div>
          {fullChartData.length > 0 && viewState.end < fullChartData.length && (
            <div className={`flex items-center space-x-2 text-sm font-mono mt-1 ${fullChartData[viewState.end].close >= fullChartData[viewState.end].open ? 'text-[#228B22]' : 'text-[#B22222]'}`}>
               <span className="font-bold">{fullChartData[viewState.end].close.toFixed(2)}</span>
               <span>{fullChartData[viewState.end].close >= fullChartData[viewState.end].open ? '+' : ''}{(fullChartData[viewState.end].close - fullChartData[viewState.end].open).toFixed(2)}</span>
            </div>
          )}
        </div>

        <div className="flex-1 min-h-0 relative" ref={chartRef} onWheel={handleWheel}>
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart 
              data={fullChartData} 
              margin={{ top: 20, right: 60, left: 10, bottom: 5 }}
              onMouseDown={handleMouseDown}
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              onMouseLeave={handleMouseUp}
              style={{ cursor: tool === 'cursor' ? (isDragging ? 'grabbing' : 'grab') : 'crosshair' }}
            >
              <defs>
                <linearGradient id="volGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#333" stopOpacity={0.8}/>
                  <stop offset="95%" stopColor="#333" stopOpacity={0.1}/>
                </linearGradient>
              </defs>

              <CartesianGrid stroke="#1a1a1a" strokeDasharray="3 3" vertical={true} horizontal={true} />

              <XAxis 
                dataKey="time" 
                tick={{ fontSize: 10, fill: '#555', fontFamily: 'JetBrains Mono' }} 
                axisLine={{ stroke: '#333' }}
                tickLine={false}
                minTickGap={50}
              />

              <YAxis 
                yAxisId="price"
                domain={yDomain} 
                orientation="right" 
                tick={{ fontSize: 10, fill: '#aaa', fontFamily: 'JetBrains Mono' }} 
                axisLine={false}
                tickLine={{ stroke: '#333' }}
                tickFormatter={(val) => val.toFixed(2)}
                width={50}
                mirror={false}
              />

              <YAxis yAxisId="volume" orientation="left" domain={[0, 'dataMax * 4']} hide />

              {showComparison && (
                 <YAxis yAxisId="compare" domain={compareDomain} orientation="left" hide={true} />
              )}

              <Tooltip 
                 content={<CustomTooltip />} 
                 cursor={{ stroke: '#ffffff', strokeWidth: 1, strokeDasharray: '4 4', opacity: 0.5 }}
                 isAnimationActive={false}
              />

              {/* Date Range Slider */}
              <Brush 
                dataKey="time"
                height={20}
                stroke="#333"
                fill="#0a0a0a"
                tickFormatter={() => ''}
                startIndex={viewState.start}
                endIndex={viewState.end}
                onChange={handleBrushChange}
              />

              <Bar dataKey="volume" yAxisId="volume" fill="url(#volGradient)" barSize={5} isAnimationActive={false} />

              {/* Wicks */}
              <Bar 
                 dataKey={(d) => [d.low, d.high]} 
                 yAxisId="price"
                 barSize={1} 
                 fill="#fff" 
                 isAnimationActive={false}
              >
                 {fullChartData.map((entry, index) => (
                    <Cell key={`wick-${index}`} fill={entry.close >= entry.open ? '#228B22' : '#B22222'} />
                 ))}
              </Bar>

              {/* Bodies */}
              <Bar 
                 dataKey={(d) => [Math.min(d.open, d.close), Math.max(d.open, d.close)]}
                 yAxisId="price"
                 barSize={8}
                 isAnimationActive={false}
              >
                 {fullChartData.map((entry, index) => (
                    <Cell key={`body-${index}`} fill={entry.close >= entry.open ? '#228B22' : '#B22222'} />
                 ))}
              </Bar>

              {showComparison && (
                 <Line 
                   yAxisId="compare"
                   type="monotone" 
                   dataKey="comparePrice" 
                   stroke="#facc15" 
                   strokeWidth={2} 
                   dot={false}
                   isAnimationActive={false}
                 />
              )}

              {indicators.sma && <Line yAxisId="price" type="monotone" dataKey="sma20" stroke="#fb923c" strokeWidth={1} dot={false} isAnimationActive={false} />}
              {indicators.ema && <Line yAxisId="price" type="monotone" dataKey="ema" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />}

              {indicators.signals && (
                <>
                  <Line yAxisId="price" type="monotone" dataKey="sma50" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} strokeOpacity={0.6} />
                  <Line yAxisId="price" type="monotone" dataKey="sma200" stroke="#a855f7" strokeWidth={1} dot={false} isAnimationActive={false} strokeOpacity={0.6} />
                  <Scatter 
                    yAxisId="price" 
                    data={signalData} 
                    shape={<RenderSignalShape />} 
                    isAnimationActive={false}
                  />
                </>
              )}

              {drawings.map((d) => (
                d.type === 'line' 
                  ? <ReferenceLine yAxisId="price" key={d.id} segment={[{ x: d.startX, y: d.startY }, { x: d.endX, y: d.endY }]} stroke="#eab308" strokeWidth={2} />
                  : <ReferenceArea yAxisId="price" key={d.id} x1={d.startX} x2={d.endX} y1={d.startY} y2={d.endY} fill="#eab308" fillOpacity={0.2} stroke="#eab308" />
              ))}

              {currentDrawing && currentDrawing.endX && (
                 currentDrawing.type === 'line'
                 ? <ReferenceLine yAxisId="price" segment={[{ x: currentDrawing.startX!, y: currentDrawing.startY! }, { x: currentDrawing.endX, y: currentDrawing.endY }]} stroke="#eab308" strokeWidth={2} strokeDasharray="3 3" />
                 : <ReferenceArea yAxisId="price" x1={currentDrawing.startX} x2={currentDrawing.endX} y1={currentDrawing.startY} y2={currentDrawing.endY} fill="#eab308" fillOpacity={0.1} stroke="#eab308" strokeDasharray="3 3" />
              )}
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {indicators.rsi && (
          <div className="h-24 shrink-0 border-t border-terminal-border/50 bg-[#0a0a0a]">
             <ResponsiveContainer width="100%" height="100%">
               <ComposedChart data={fullChartData.slice(viewState.start, viewState.end + 1)} margin={{ top: 5, right: 60, left: 10, bottom: 0 }}>
                 <CartesianGrid stroke="#222" strokeDasharray="3 3" vertical={false} />
                 <YAxis domain={[0, 100]} orientation="right" tick={{ fontSize: 9, fill: '#666' }} axisLine={false} tickLine={false} width={50} ticks={[30, 70]} />
                 <Tooltip content={<CustomTooltip />} cursor={{ stroke: '#444', strokeDasharray: '4 4' }} />
                 <ReferenceLine y={70} stroke="#444" strokeDasharray="3 3" />
                 <ReferenceLine y={30} stroke="#444" strokeDasharray="3 3" />
                 <Line type="monotone" dataKey="rsi" stroke="#c084fc" strokeWidth={1} dot={false} isAnimationActive={false} />
               </ComposedChart>
             </ResponsiveContainer>
          </div>
        )}

        {indicators.macd && (
          <div className="h-24 shrink-0 border-t border-terminal-border/50 bg-[#0a0a0a]">
             <ResponsiveContainer width="100%" height="100%">
               <ComposedChart data={fullChartData.slice(viewState.start, viewState.end + 1)} margin={{ top: 5, right: 60, left: 10, bottom: 0 }}>
                 <CartesianGrid stroke="#222" strokeDasharray="3 3" vertical={false} />
                 <YAxis orientation="right" tick={{ fontSize: 9, fill: '#666' }} axisLine={false} tickLine={false} width={50} />
                 <Tooltip content={<CustomTooltip />} cursor={{ stroke: '#444', strokeDasharray: '4 4' }} />
                 <ReferenceLine y={0} stroke="#444" />
                 <Bar dataKey="macdHistogram" fill="#444" isAnimationActive={false}>
                    {fullChartData.slice(viewState.start, viewState.end + 1).map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={(entry as any).macdHistogram > 0 ? '#22c55e' : '#ef4444'} />
                    ))}
                 </Bar>
                 <Line type="monotone" dataKey="macdLine" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />
                 <Line type="monotone" dataKey="macdSignal" stroke="#f97316" strokeWidth={1} dot={false} isAnimationActive={false} />
               </ComposedChart>
             </ResponsiveContainer>
          </div>
        )}
      </div>
    </Card>
  );
};

