  const [isPaper, setIsPaper] = useState(true);

  // Sync selected quote with real-time updates
  useEffect(() => {
    const unsubscribe = marketService.subscribe((quotes) => {
      const quote = quotes.find(q => q.symbol === selectedSymbol);
      if (quote) {
        setSelectedQuote(quote);
      }
    });
    return unsubscribe;
  }, [selectedSymbol]);

