        <div className="w-full lg:w-[55%] h-full flex flex-col border-b lg:border-b-0 lg:border-r border-terminal-border">

          {/* Top: Chart (60% height) */}
          <div className="flex-[3] min-h-[300px] lg:min-h-0 border-b border-terminal-border p-1 relative">
            <ChartWidget symbol={selectedSymbol} />
          </div>

          {/* Bottom: Portfolio (40% height) */}
          <div className="flex-[2] min-h-[200px] lg:min-h-0 p-1 relative">
