            <OrderTicket quote={selectedQuote} />
          </div>

          {/* Middle: AI Prediction (Flexible approx 35%) */}
          <div className="flex-1 min-h-[200px] border-b border-terminal-border p-1">
            <PredictionWidget symbol={selectedSymbol} />
          </div>

          {/* Bottom: News (Flexible approx 35%) */}
          <div className="flex-1 min-h-[200px] p-1">
            <NewsFeed />
          </div>
        </div>

      </main>

      {/* Command Palette Modal */}
      <CommandPalette 
        isOpen={isCommandOpen} 
        onClose={() => setIsCommandOpen(false)}
        onSelect={setSelectedSymbol}
      />
    </div>
  );
}

export default App;

