import React, { useEffect, useState } from 'react';
import { Card } from './Card';
import { BrainCircuit, Info } from 'lucide-react';
import {
  ResponsiveContainer,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Line
} from 'recharts';

interface PredictionWidgetProps {
  symbol?: string;
}

export const PredictionWidget: React.FC<PredictionWidgetProps> = ({ symbol = 'AAPL' }) => {
  const [data, setData] = useState<any[]>([]);
  const [lastPred, setLastPred] = useState<number>(0);

  useEffect(() => {
    // Generate mock prediction data based on symbol
    const generatePredictionData = () => {
      const historyPoints = 30;
      const futurePoints = 15;
      // Semi-random start price based on symbol length to keep it visually stable per symbol
      const startPrice = 100 + (symbol.length * 10); 
      const volatility = 1.5;

      const newData = [];
      let currentPrice = startPrice;

      // Generate History
      for (let i = 0; i < historyPoints; i++) {
        const change = (Math.random() - 0.5) * volatility * 2;
        currentPrice += change;
        newData.push({
          step: i,
          type: 'History',
          price: currentPrice,
          prediction: null,
          range: null
        });
      }

      // Generate Prediction
      // Simple trend based on symbol char code to determine up/down bias
      const bias = (symbol.charCodeAt(0) % 2 === 0) ? 0.8 : -0.8;
      let predPrice = currentPrice;

      // Connect the lines
      newData[historyPoints - 1].prediction = currentPrice;
      newData[historyPoints - 1].range = [currentPrice, currentPrice];

      for (let i = 1; i <= futurePoints; i++) {
        const stepIndex = historyPoints + i - 1;

        // Random walk with bias
        predPrice += bias + ((Math.random() - 0.5) * volatility);

        // Widening confidence interval
        const confidence = i * 1.5; 

        newData.push({
          step: stepIndex,
          type: 'Prediction',
          price: null,
          prediction: predPrice,
          range: [predPrice - confidence, predPrice + confidence]
        });
      }

      setData(newData);
      setLastPred(predPrice);
    };

    generatePredictionData();
  }, [symbol]);

  return (
    <Card 
      title={`AI Price Forecast: ${symbol}`} 
      className="h-full flex flex-col"
      actions={
        <div className="flex items-center gap-1 text-[10px] text-terminal-muted bg-white/5 px-2 py-0.5 rounded border border-white/10">
          <BrainCircuit size={10} className="text-purple-400" />
          <span>MODEL: PROPHET-V2</span>
        </div>
      }
    >
      <div className="flex-1 flex flex-col p-2 relative min-h-0">

        {/* Overlay Price Target */}
        <div className="absolute top-2 right-4 z-10 text-right">
          <div className="text-[10px] text-gray-500 uppercase">Proj. Close</div>
          <div className="text-xl font-bold font-mono text-purple-400">
             {lastPred.toFixed(2)}
          </div>
        </div>

        {/* Chart Container */}
        <div className="flex-1 min-h-0 relative">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={data} margin={{ top: 10, right: 5, left: -20, bottom: 0 }}>
              <defs>
                <linearGradient id="predGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid stroke="#1a1a1a" strokeDasharray="3 3" vertical={false} />

              <XAxis dataKey="step" hide />

              <YAxis 
                domain={['auto', 'auto']} 
                tick={{ fontSize: 9, fill: '#555' }} 
                axisLine={false} 
                tickLine={false} 
                tickFormatter={(val) => val.toFixed(0)}
              />

              <Tooltip 
                contentStyle={{ backgroundColor: '#111', borderColor: '#333', fontSize: '10px' }}
                itemStyle={{ padding: 0 }}
                formatter={(val: any, name: string) => {
                  if (Array.isArray(val)) return null; // Hide range in tooltip for clarity
                  return typeof val === 'number' ? val.toFixed(2) : val;
                }}
                labelStyle={{ display: 'none' }}
              />

              {/* Confidence Interval Area */}
              <Area
                dataKey="range"
                stroke="none"
                fill="url(#predGradient)"
                isAnimationActive={false}
              />

              {/* History Line */}
              <Line 
                type="monotone" 
                dataKey="price" 
                stroke="#00ff41" 
                strokeWidth={2} 
                dot={false}
                isAnimationActive={false}
              />

              {/* Prediction Line */}
              <Line 
                type="monotone" 
                dataKey="prediction" 
                stroke="#c084fc" 
                strokeWidth={2} 
                strokeDasharray="3 3"
                dot={false}
                isAnimationActive={false}
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        {/* Disclaimer Footer */}
        <div className="mt-2 flex items-center gap-2 p-2 bg-blue-900/10 border border-blue-900/30 rounded">
          <Info size={12} className="text-blue-400 shrink-0" />
          <p className="text-[9px] text-gray-500 leading-tight">
            <span className="text-blue-400 font-bold">SIMULATION ONLY:</span> This projection is generated by a placeholder algorithm. Real-world application requires integration with a trained Time Series Forecasting model (e.g., ARIMA, LSTM).
          </p>
        </div>
      </div>
    </Card>
  );
};

