import React, { useState, useEffect } from 'react';
import { Card } from './Card';
import { Quote } from '../types';
import { portfolioService } from '../services/portfolioService';
import { DollarSign, Hash, CheckCircle2, XCircle, ShieldCheck, Zap } from 'lucide-react';

interface OrderTicketProps {
  quote: Quote | undefined;
}

export const OrderTicket: React.FC<OrderTicketProps> = ({ quote }) => {
  const [side, setSide] = useState<'BUY' | 'SELL'>('BUY');
  const [orderType, setOrderType] = useState<'MARKET' | 'LIMIT' | 'STOP'>('LIMIT');
  const [quantity, setQuantity] = useState<number>(100);
  const [price, setPrice] = useState<string>('');
  const [isPaper, setIsPaper] = useState(true);
  const [statusMsg, setStatusMsg] = useState<{type: 'success'|'error', text: string} | null>(null);

  useEffect(() => {
    const unsubscribe = portfolioService.subscribeMode(setIsPaper);
    return unsubscribe;
  }, []);

  useEffect(() => {
    if (quote && price === '' && orderType === 'LIMIT') {
      setPrice(quote.price.toFixed(2));
    }
  }, [quote, orderType]);

  useEffect(() => {
    if (statusMsg) {
      const timer = setTimeout(() => setStatusMsg(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [statusMsg]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!quote) { setStatusMsg({ type: 'error', text: 'No Symbol' }); return; }
    const executionPrice = orderType === 'MARKET' ? quote.price : parseFloat(price);
    if (isNaN(executionPrice) || executionPrice <= 0) { setStatusMsg({ type: 'error', text: 'Invalid Price' }); return; }
    if (quantity <= 0) { setStatusMsg({ type: 'error', text: 'Invalid Qty' }); return; }
    const result = portfolioService.executeTrade(quote.symbol, side, quantity, executionPrice);
    if (result.success) { setStatusMsg({ type: 'success', text: result.message }); } 
    else { setStatusMsg({ type: 'error', text: result.message }); }
  };

  const total = quote ? (quantity * (orderType === 'MARKET' ? quote.price : parseFloat(price) || 0)).toFixed(2) : '0.00';

  return (
    <Card title="Order Entry" className="h-full flex flex-col">
      <div className="p-2 space-y-2 font-mono text-sm flex-1 overflow-hidden">
        {/* Symbol Header */}
        <div className="flex justify-between items-center border-b border-terminal-border pb-1">
          <div className="flex items-baseline gap-2">
            <span className="text-lg font-bold text-terminal-accent">{quote?.symbol || '---'}</span>
            <span className="text-[10px] text-terminal-muted">{quote?.price.toFixed(2)}</span>
          </div>
          <div className="text-[10px] flex gap-2">
             <span className="text-terminal-muted">Bid <span className="text-terminal-up">{quote?.bid.toFixed(2)}</span></span>
             <span className="text-terminal-muted">Ask <span className="text-terminal-down">{quote?.ask.toFixed(2)}</span></span>
          </div>
        </div>

        {/* Side Selection */}
        <div className="flex rounded bg-terminal-bg border border-terminal-border p-0.5">
          <button onClick={() => setSide('BUY')} className={`flex-1 py-0.5 text-center font-bold rounded text-[10px] uppercase transition-all ${side === 'BUY' ? 'bg-terminal-up text-black' : 'text-terminal-muted hover:text-terminal-text'}`}>Buy</button>
          <button onClick={() => setSide('SELL')} className={`flex-1 py-0.5 text-center font-bold rounded text-[10px] uppercase transition-all ${side === 'SELL' ? 'bg-terminal-down text-white' : 'text-terminal-muted hover:text-terminal-text'}`}>Sell</button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-2">
          {/* Order Type */}
          <div className="grid grid-cols-3 gap-1">
             {['MARKET', 'LIMIT', 'STOP'].map((t) => (
               <button key={t} type="button" onClick={() => setOrderType(t as any)} className={`py-0.5 text-[9px] border border-terminal-border rounded uppercase ${orderType === t ? 'bg-terminal-accent/10 text-terminal-accent border-terminal-accent' : 'text-terminal-muted hover:border-terminal-muted'}`}>{t}</button>
             ))}
          </div>

          <div className="flex gap-2">
            {/* Quantity */}
            <div className="flex-1 space-y-0.5">
              <label className="text-[9px] text-terminal-muted uppercase flex items-center gap-1"><Hash size={8} /> Qty</label>
              <input type="number" value={quantity} onChange={(e) => setQuantity(Number(e.target.value))} className="w-full bg-white dark:bg-black border border-terminal-border p-1 text-right text-terminal-text text-xs focus:border-terminal-accent focus:outline-none font-mono" />
            </div>

            {/* Price (Conditional) */}
            <div className="flex-1 space-y-0.5">
               {orderType !== 'MARKET' ? (
                <>
                  <label className="text-[9px] text-terminal-muted uppercase flex items-center gap-1"><DollarSign size={8} /> Price</label>
                  <input type="number" step="0.01" value={price} onChange={(e) => setPrice(e.target.value)} className="w-full bg-white dark:bg-black border border-terminal-border p-1 text-right text-terminal-text text-xs focus:border-terminal-accent focus:outline-none font-mono" />
                </>
               ) : (
                <>
                  <label className="text-[9px] text-terminal-muted uppercase flex items-center gap-1">Est Price</label>
                  <div className="w-full bg-black/5 dark:bg-white/5 border border-transparent p-1 text-right text-terminal-muted text-xs font-mono">{quote?.price.toFixed(2)}</div>
                </>
               )}
            </div>
          </div>

          {/* Submit Button */}
          <button type="submit" className={`w-full py-1.5 font-bold text-xs uppercase tracking-wider rounded shadow active:scale-[0.98] transition-transform ${side === 'BUY' ? 'bg-terminal-up text-black hover:bg-green-400' : 'bg-terminal-down text-white hover:bg-red-500'}`}>Submit ({total})</button>
        </form>

        {/* Status Messages */}
        {statusMsg && (
          <div className={`p-1 rounded text-[9px] flex items-center gap-2 ${statusMsg.type === 'success' ? 'bg-green-500/10 text-green-600 dark:text-green-400' : 'bg-red-500/10 text-red-600 dark:text-red-400'}`}>
            {statusMsg.type === 'success' ? <CheckCircle2 size={10} /> : <XCircle size={10} />}
            <span className="truncate">{statusMsg.text}</span>
          </div>
        )}
      </div>

      {/* Footer / Status */}
      <div className={`px-2 py-1 border-t text-[9px] flex items-center gap-1 font-bold ${
        isPaper 
          ? 'bg-yellow-100 dark:bg-[#1a1a10] text-yellow-600 dark:text-yellow-500' 
          : 'bg-green-100 dark:bg-[#101a10] text-green-600 dark:text-green-500'
      }`}>
        {isPaper ? <ShieldCheck size={10} /> : <Zap size={10} />}
        <span>{isPaper ? 'SIM' : 'LIVE'}</span>
      </div>
    </Card>
  );
};

