import React, { useEffect, useState } from 'react';
import { Card } from './Card';
import { BrainCircuit, Info } from 'lucide-react';
import {
  ResponsiveContainer,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Line
} from 'recharts';

interface PredictionWidgetProps {
  symbol?: string;
  theme?: 'dark' | 'light';
}

export const PredictionWidget: React.FC<PredictionWidgetProps> = ({ symbol = 'AAPL', theme = 'dark' }) => {
  const [data, setData] = useState<any[]>([]);
  const [lastPred, setLastPred] = useState<number>(0);

  useEffect(() => {
    // Generate mock prediction data based on symbol
    const generatePredictionData = () => {
      const historyPoints = 30;
      const futurePoints = 15;
      const startPrice = 100 + (symbol.length * 10); 
      const volatility = 1.5;
      const newData = [];
      let currentPrice = startPrice;

      // Generate History
      for (let i = 0; i < historyPoints; i++) {
        const change = (Math.random() - 0.5) * volatility * 2;
        currentPrice += change;
        newData.push({ step: i, type: 'History', price: currentPrice, prediction: null, range: null });
      }

      // Generate Prediction
      const bias = (symbol.charCodeAt(0) % 2 === 0) ? 0.8 : -0.8;
      let predPrice = currentPrice;
      newData[historyPoints - 1].prediction = currentPrice;
      newData[historyPoints - 1].range = [currentPrice, currentPrice];

      for (let i = 1; i <= futurePoints; i++) {
        const stepIndex = historyPoints + i - 1;
        predPrice += bias + ((Math.random() - 0.5) * volatility);
        const confidence = i * 1.5; 
        newData.push({ step: stepIndex, type: 'Prediction', price: null, prediction: predPrice, range: [predPrice - confidence, predPrice + confidence] });
      }

      setData(newData);
      setLastPred(predPrice);
    };

    generatePredictionData();
  }, [symbol]);

  const gridColor = theme === 'dark' ? '#1a1a1a' : '#e5e7eb';
  const axisColor = theme === 'dark' ? '#555' : '#9ca3af';

  return (
    <Card 
      title={`AI Price Forecast: ${symbol}`} 
      className="h-full flex flex-col"
      actions={
        <div className="flex items-center gap-1 text-[10px] text-terminal-muted bg-white/5 px-2 py-0.5 rounded border border-white/10">
          <BrainCircuit size={10} className="text-purple-400" />
          <span>MODEL: PROPHET-V2</span>
        </div>
      }
    >
      <div className="flex-1 flex flex-col p-2 relative min-h-0 bg-terminal-bg transition-colors duration-200">

        {/* Overlay Price Target */}
        <div className="absolute top-2 right-4 z-10 text-right">
          <div className="text-[10px] text-terminal-muted uppercase">Proj. Close</div>
          <div className="text-xl font-bold font-mono text-purple-400">
             {lastPred.toFixed(2)}
          </div>
        </div>

        {/* Chart Container */}
        <div className="flex-1 min-h-0 relative">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={data} margin={{ top: 10, right: 5, left: -20, bottom: 0 }}>
              <defs>
                <linearGradient id="predGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid stroke={gridColor} strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="step" hide />
              <YAxis domain={['auto', 'auto']} tick={{ fontSize: 9, fill: axisColor }} axisLine={false} tickLine={false} tickFormatter={(val) => val.toFixed(0)} />
              <Tooltip 
                contentStyle={{ backgroundColor: 'var(--color-panel)', borderColor: 'var(--color-border)', fontSize: '10px' }}
                itemStyle={{ padding: 0, color: 'var(--color-text)' }}
                formatter={(val: any, name: string) => {
                  if (Array.isArray(val)) return null; 
                  return typeof val === 'number' ? val.toFixed(2) : val;
                }}
                labelStyle={{ display: 'none' }}
              />
              <Area dataKey="range" stroke="none" fill="url(#predGradient)" isAnimationActive={false} />
              <Line type="monotone" dataKey="price" stroke="var(--color-up)" strokeWidth={2} dot={false} isAnimationActive={false} />
              <Line type="monotone" dataKey="prediction" stroke="#c084fc" strokeWidth={2} strokeDasharray="3 3" dot={false} isAnimationActive={false} />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        {/* Disclaimer Footer */}
        <div className="mt-2 flex items-center gap-2 p-2 bg-blue-500/10 border border-blue-500/30 rounded">
          <Info size={12} className="text-blue-500 shrink-0" />
          <p className="text-[9px] text-terminal-muted leading-tight">
            <span className="text-blue-500 font-bold">SIMULATION ONLY:</span> This projection is generated by a placeholder algorithm. Real-world application requires integration with a trained Time Series Forecasting model.
          </p>
        </div>
      </div>
    </Card>
  );
};

import React, { useEffect, useState } from 'react';
import { Card } from './Card';
import { marketService } from '../services/marketService';
import { portfolioService } from '../services/portfolioService';
import { Quote, Portfolio, Position } from '../types';
import { TrendingUp, TrendingDown, RefreshCcw } from 'lucide-react';

export const PortfolioWidget: React.FC = () => {
  const [portfolio, setPortfolio] = useState<Portfolio | null>(null);
  const [quotes, setQuotes] = useState<Quote[]>([]);
  const [isPaper, setIsPaper] = useState(true);

  useEffect(() => {
    const unsubPortfolio = portfolioService.subscribe(setPortfolio);
    const unsubMarket = marketService.subscribe(setQuotes);
    const unsubMode = portfolioService.subscribeMode(setIsPaper);
    return () => {
      unsubPortfolio();
      unsubMarket();
      unsubMode();
    };
  }, []);

  if (!portfolio) return null;

  let equityValue = 0;
  let totalPnL = 0;

  const positionRows = Object.values(portfolio.positions).map((pos: Position) => {
    const quote = quotes.find(q => q.symbol === pos.symbol);
    const currentPrice = quote ? quote.price : pos.averageEntryPrice;
    const marketValue = pos.quantity * currentPrice;
    const pnl = (currentPrice - pos.averageEntryPrice) * pos.quantity;
    const pnlPercent = ((currentPrice - pos.averageEntryPrice) / pos.averageEntryPrice) * 100;

    equityValue += marketValue;
    totalPnL += pnl;

    return { ...pos, currentPrice, marketValue, pnl, pnlPercent };
  });

  const totalNetWorth = portfolio.cash + equityValue;
  const isPositive = totalPnL >= 0;

  return (
    <Card 
      title={`Portfolio - ${isPaper ? 'Paper Trading' : 'Live Account'}`} 
      className="h-full flex flex-col"
      actions={
        isPaper && (
          <button 
            onClick={() => portfolioService.resetPaperAccount()}
            className="text-[10px] text-terminal-muted hover:text-terminal-text flex items-center gap-1 hover:bg-black/5 dark:hover:bg-white/10 px-2 py-0.5 rounded transition-colors"
            title="Reset Paper Account"
          >
            <RefreshCcw size={10} />
            <span>Reset</span>
          </button>
        )
      }
    >
      <div className={`flex items-center justify-between p-4 border-b border-terminal-border relative overflow-hidden ${isPaper ? 'bg-yellow-50 dark:bg-[#1a1a10]' : 'bg-green-50 dark:bg-[#101a10]'}`}>
        <div className={`absolute top-0 right-0 w-32 h-full opacity-10 blur-xl ${isPaper ? 'bg-yellow-500' : 'bg-green-500'}`}></div>

        <div className="relative z-10">
          <span className="text-xs text-terminal-muted uppercase tracking-wider block mb-1">Net Liquidity</span>
          <span className="text-2xl font-bold text-terminal-text font-mono tracking-tight">
            ${totalNetWorth.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
          </span>
        </div>
        <div className="text-right relative z-10">
          <span className="text-xs text-terminal-muted uppercase tracking-wider block mb-1">Day P&L</span>
          <div className={`text-xl font-bold font-mono flex items-center justify-end gap-2 ${isPositive ? 'text-terminal-up' : 'text-terminal-down'}`}>
            {isPositive ? <TrendingUp size={16} /> : <TrendingDown size={16} />}
            ${Math.abs(totalPnL).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
          </div>
        </div>
        <div className="text-right hidden sm:block relative z-10">
          <span className="text-xs text-terminal-muted uppercase tracking-wider block mb-1">Cash Balance</span>
          <span className="text-lg font-mono text-terminal-accent">
            ${portfolio.cash.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
          </span>
        </div>
      </div>

      <div className="flex-1 overflow-auto bg-terminal-bg">
        <table className="w-full text-left border-collapse">
          <thead className="bg-terminal-panel sticky top-0 z-10 text-[10px] uppercase text-terminal-muted font-semibold tracking-wider">
            <tr>
              <th className="p-2 border-b border-terminal-border">Symbol</th>
              <th className="p-2 text-right border-b border-terminal-border">Qty</th>
              <th className="p-2 text-right border-b border-terminal-border">Avg Price</th>
              <th className="p-2 text-right border-b border-terminal-border">Mark</th>
              <th className="p-2 text-right border-b border-terminal-border hidden xl:table-cell">Mkt Value</th>
              <th className="p-2 text-right border-b border-terminal-border">Unr. P&L</th>
            </tr>
          </thead>
          <tbody>
            {positionRows.length === 0 ? (
              <tr>
                <td colSpan={6} className="p-8 text-center text-terminal-muted text-xs italic">
                  No open positions. Use the order ticket to trade.
                </td>
              </tr>
            ) : (
              positionRows.map((pos) => (
                <tr key={pos.symbol} className="border-b border-terminal-border/50 hover:bg-black/5 dark:hover:bg-white/5 text-xs">
                  <td className="p-2 font-bold text-terminal-text font-mono">{pos.symbol}</td>
                  <td className="p-2 text-right font-mono text-terminal-muted">{pos.quantity.toLocaleString()}</td>
                  <td className="p-2 text-right font-mono text-terminal-muted">{pos.averageEntryPrice.toFixed(2)}</td>
                  <td className="p-2 text-right font-mono text-terminal-text">{pos.currentPrice.toFixed(2)}</td>
                  <td className="p-2 text-right font-mono text-terminal-muted hidden xl:table-cell">
                    {pos.marketValue.toLocaleString('en-US', { maximumFractionDigits: 0 })}
                  </td>
                  <td className={`p-2 text-right font-mono ${pos.pnl >= 0 ? 'text-terminal-up' : 'text-terminal-down'}`}>
                    <div className="flex flex-col leading-tight">
                       <span>{pos.pnl >= 0 ? '+' : ''}{pos.pnl.toLocaleString('en-US', { maximumFractionDigits: 2 })}</span>
                       <span className="text-[9px] opacity-75">{pos.pnlPercent.toFixed(2)}%</span>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </Card>
  );
};

import React, { useState, useEffect } from 'react';
import { Search, Command, X } from 'lucide-react';
import { INITIAL_QUOTES } from '../constants';

interface CommandPaletteProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (symbol: string) => void;
}

export const CommandPalette: React.FC<CommandPaletteProps> = ({ isOpen, onClose, onSelect }) => {
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);

  const filtered = INITIAL_QUOTES.filter(q => 
    q.symbol.toLowerCase().includes(query.toLowerCase()) || 
    q.name.toLowerCase().includes(query.toLowerCase())
  ).slice(0, 5);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isOpen) return;
      if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIndex(prev => (prev + 1) % filtered.length); } 
      else if (e.key === 'ArrowUp') { e.preventDefault(); setSelectedIndex(prev => (prev - 1 + filtered.length) % filtered.length); } 
      else if (e.key === 'Enter') { e.preventDefault(); if (filtered[selectedIndex]) { onSelect(filtered[selectedIndex].symbol); onClose(); } } 
      else if (e.key === 'Escape') { onClose(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, filtered, selectedIndex, onSelect, onClose]);

  useEffect(() => { setSelectedIndex(0); }, [query]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-start justify-center pt-[20vh]">
      <div className="w-[600px] bg-terminal-panel border border-terminal-border rounded-lg shadow-2xl overflow-hidden flex flex-col">
        <div className="flex items-center p-3 border-b border-terminal-border">
          <Command className="text-terminal-muted mr-2" size={18} />
          <input 
            autoFocus
            type="text"
            placeholder="Search commands, symbols, or news (e.g. 'AAPL', 'Buy ES', 'Macro')..."
            className="flex-1 bg-transparent border-none outline-none text-terminal-text placeholder-terminal-muted font-mono text-sm"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
          />
          <button onClick={onClose} className="text-terminal-muted hover:text-terminal-text">
            <X size={18} />
          </button>
        </div>
        <div className="max-h-[300px] overflow-y-auto bg-terminal-bg">
          {filtered.length === 0 ? (
             <div className="p-8 text-center text-terminal-muted text-sm">No results found.</div>
          ) : (
            <ul>
              {filtered.map((item, index) => (
                <li 
                  key={item.symbol}
                  className={`flex items-center justify-between p-3 cursor-pointer ${index === selectedIndex ? 'bg-terminal-accent/10 border-l-2 border-terminal-accent' : 'hover:bg-black/5 dark:hover:bg-white/5 border-l-2 border-transparent'}`}
                  onClick={() => { onSelect(item.symbol); onClose(); }}
                >
                  <div>
                    <span className="font-bold text-terminal-text font-mono mr-2">{item.symbol}</span>
                    <span className="text-terminal-muted text-sm">{item.name}</span>
                  </div>
                  <div className="text-xs font-mono text-terminal-muted">{item.sector}</div>
                </li>
              ))}
            </ul>
          )}
        </div>
        <div className="bg-terminal-panel p-2 border-t border-terminal-border flex justify-between text-[10px] text-terminal-muted">
           <span>Navigate <b className="text-terminal-text">↑↓</b></span>
           <span>Select <b className="text-terminal-text">↵</b></span>
           <span>Close <b className="text-terminal-text">ESC</b></span>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  ComposedChart, 
  Bar,
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  ReferenceLine,
  ReferenceArea,
  Cell,
  Scatter,
  Brush
} from 'recharts';
import { Card } from './Card';
import { TimeFrame } from '../types';
import { generateChartData } from '../constants';
import { Activity, Pencil, Square, Trash2, MousePointer2, Layers, PenTool, Undo2 } from 'lucide-react';

interface ChartWidgetProps {
  symbol: string;
  theme?: 'dark' | 'light';
}

interface Drawing {
  id: string;
  type: 'line' | 'box';
  startX: string; // Time label
  startY: number; // Price
  endX: string;
  endY: number;
}

type ToolType = 'cursor' | 'line' | 'box';

interface Signal {
  time: string;
  price: number;
  type: 'BUY' | 'SELL';
  desc: string;
}

// --- Indicator Helpers ---
const calculateSMA = (data: any[], period: number) => {
  return data.map((item, index, arr) => {
    if (index < period - 1) return { ...item, [`sma${period}`]: null };
    const slice = arr.slice(index - period + 1, index + 1);
    const sum = slice.reduce((acc, curr) => acc + curr.close, 0);
    return { ...item, [`sma${period}`]: sum / period };
  });
};

const calculateEMA = (data: any[], period: number) => {
  const k = 2 / (period + 1);
  let ema = data[0].close;
  return data.map((item, index) => {
    if (index === 0) return { ...item, ema: item.close };
    ema = (item.close - ema) * k + ema;
    return { ...item, ema };
  });
};

const calculateRSI = (data: any[], period: number = 14) => {
  let gains = 0;
  let losses = 0;
  for (let i = 1; i <= period; i++) {
    const change = data[i].close - data[i - 1].close;
    if (change > 0) gains += change;
    else losses -= change;
  }
  let avgGain = gains / period;
  let avgLoss = losses / period;

  return data.map((item, index) => {
    if (index < period) return { ...item, rsi: null };
    if (index > period) {
      const change = item.close - data[index - 1].close;
      const gain = change > 0 ? change : 0;
      const loss = change < 0 ? -change : 0;
      avgGain = (avgGain * (period - 1) + gain) / period;
      avgLoss = (avgLoss * (period - 1) + loss) / period;
    }
    const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    const rsi = 100 - (100 / (1 + rs));
    return { ...item, rsi };
  });
};

const calculateMACD = (data: any[]) => {
  const ema12Data = calculateEMA(data, 12);
  const ema26Data = calculateEMA(data, 26);
  const macdData = data.map((item, i) => {
    const ema12 = ema12Data[i].ema;
    const ema26 = ema26Data[i].ema;
    return { ...item, macdLine: (ema12 && ema26) ? ema12 - ema26 : null };
  });
  const period = 9;
  const k = 2 / (period + 1);
  let signal = 0;
  let firstValidIndex = -1;
  return macdData.map((item, i) => {
    if (item.macdLine === null) return { ...item, macdSignal: null, macdHistogram: null };
    if (firstValidIndex === -1) {
      firstValidIndex = i;
      signal = item.macdLine;
      return { ...item, macdSignal: signal, macdHistogram: 0 };
    }
    signal = (item.macdLine - signal) * k + signal;
    return { ...item, macdSignal: signal, macdHistogram: item.macdLine - signal };
  });
};

const analyzeTrendSignals = (data: any[]): Signal[] => {
  const signals: Signal[] = [];

  for (let i = 1; i < data.length; i++) {
    const prev = data[i-1];
    const curr = data[i];

    if (prev.sma50 && prev.sma200 && curr.sma50 && curr.sma200) {
      if (prev.sma50 <= prev.sma200 && curr.sma50 > curr.sma200) {
        signals.push({ time: curr.time, price: curr.low * 0.995, type: 'BUY', desc: 'Golden Cross' });
      } else if (prev.sma50 >= prev.sma200 && curr.sma50 < curr.sma200) {
        signals.push({ time: curr.time, price: curr.high * 1.005, type: 'SELL', desc: 'Death Cross' });
      }
    }
  }
  return signals;
};

export const ChartWidget: React.FC<ChartWidgetProps> = ({ symbol, theme = 'dark' }) => {
  // Data State
  const [rawData, setRawData] = useState<any[]>([]);
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.M5);

  // View State (Zoom/Pan)
  const [viewState, setViewState] = useState({ start: 0, end: 100 }); 
  const MIN_ZOOM = 20; 
  const DEFAULT_ZOOM = 100;

  // UI State
  const [indicators, setIndicators] = useState({ sma: false, ema: false, rsi: false, macd: false, signals: false });
  const [showComparison, setShowComparison] = useState(false);
  const [showToolbar, setShowToolbar] = useState(false);

  // Drawing State
  const [tool, setTool] = useState<ToolType>('cursor');
  const [drawings, setDrawings] = useState<Drawing[]>([]);
  const [currentDrawing, setCurrentDrawing] = useState<Partial<Drawing> | null>(null);

  // Interaction State
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState<number | null>(null); 

  const chartRef = useRef<HTMLDivElement>(null);

  // Theme constants
  const axisColor = theme === 'dark' ? '#555' : '#9ca3af';
  const gridColor = theme === 'dark' ? '#1a1a1a' : '#e5e7eb';
  const brushStroke = theme === 'dark' ? '#333' : '#d1d5db';
  const brushFill = theme === 'dark' ? '#0a0a0a' : '#f9fafb';
  const textColor = theme === 'dark' ? '#e5e5e5' : '#1f2937';

  // Initialize Data
  useEffect(() => {
    const totalPoints = 500;
    const newData = generateChartData(totalPoints);
    setRawData(newData);
    setViewState({ start: totalPoints - DEFAULT_ZOOM, end: totalPoints - 1 });
    setDrawings([]);
    setCurrentDrawing(null);
  }, [symbol, timeframe]);

  // Process Indicators & Comparison
  const fullChartData = useMemo(() => {
    if (!rawData.length) return [];
    let processed = [...rawData];
    processed = calculateSMA(processed, 50);
    processed = calculateSMA(processed, 200);
    if (indicators.sma) processed = calculateSMA(processed, 20);
    if (indicators.ema) processed = calculateEMA(processed, 20);
    if (indicators.rsi) processed = calculateRSI(processed, 14);
    if (indicators.macd) processed = calculateMACD(processed);
    return processed;
  }, [rawData, indicators]);

  const signalData = useMemo(() => {
    if (!indicators.signals) return [];
    return analyzeTrendSignals(fullChartData);
  }, [fullChartData, indicators.signals]);

  const yDomain = useMemo(() => {
    if (!fullChartData.length) return [0, 0];
    const visibleSlice = fullChartData.slice(viewState.start, viewState.end + 1);
    if (!visibleSlice.length) return [0, 0];
    const highs = visibleSlice.map(d => d.high);
    const lows = visibleSlice.map(d => d.low);
    const min = Math.min(...lows);
    const max = Math.max(...highs);
    const padding = (max - min) * 0.1;
    return [min - padding, max + padding];
  }, [fullChartData, viewState]);

  const compareDomain = useMemo(() => {
    if (!showComparison || !fullChartData.length) return [0, 0];
    const visibleSlice = fullChartData.slice(viewState.start, viewState.end + 1);
    const prices = visibleSlice.map(d => d.comparePrice);
    const min = Math.min(...prices);
    const max = Math.max(...prices);
    const padding = (max - min) * 0.1;
    return [min - padding, max + padding];
  }, [fullChartData, showComparison, viewState]);

  const handleBrushChange = (e: any) => {
    if (e.startIndex !== undefined && e.endIndex !== undefined) {
      setViewState({ start: e.startIndex, end: e.endIndex });
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    if (tool !== 'cursor') return;
    const zoomSpeed = 0.5;
    const delta = Math.sign(e.deltaY) * Math.round(Math.abs(e.deltaY) * zoomSpeed);
    setViewState(prev => {
      const currentLength = prev.end - prev.start;
      let newLength = currentLength + delta;
      if (newLength < MIN_ZOOM) newLength = MIN_ZOOM;
      if (newLength > fullChartData.length) newLength = fullChartData.length;
      const center = prev.start + currentLength / 2;
      let newStart = center - newLength / 2;
      let newEnd = center + newLength / 2;
      if (newEnd >= fullChartData.length) { newEnd = fullChartData.length - 1; newStart = newEnd - newLength; }
      if (newStart < 0) { newStart = 0; newEnd = newLength; }
      return { start: Math.round(newStart), end: Math.round(newEnd) };
    });
  };

  const getPriceFromY = (chartY: number, height: number) => {
    const [min, max] = yDomain;
    if (min === max) return min;
    const top = 20; const bottom = 40; 
    const chartHeight = height - top - bottom;
    if (chartHeight <= 0) return 0;
    const relativeY = chartY - top;
    const ratio = Math.max(0, Math.min(1, relativeY / chartHeight));
    const priceRange = max - min;
    return max - (ratio * priceRange);
  };

  const handleMouseDown = (e: any) => {
    if (!e) return;
    if (tool === 'cursor') { setIsDragging(true); setDragStart(e.chartX); return; }
    if (e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing({ id: Date.now().toString(), type: tool === 'line' ? 'line' : 'box', startX: e.activeLabel, startY: price, endX: e.activeLabel, endY: price });
    }
  };

  const handleMouseMove = (e: any) => {
    if (!e) return;
    if (isDragging && tool === 'cursor' && dragStart !== null && e.chartX) { return; }
    if (currentDrawing && e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing(prev => ({ ...prev, endX: e.activeLabel, endY: price }));
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false); setDragStart(null);
    if (currentDrawing && currentDrawing.endX && currentDrawing.endY) {
      setDrawings(prev => [...prev, currentDrawing as Drawing]);
      setCurrentDrawing(null);
    }
  };

  const handleUndo = () => {
    setDrawings(prev => prev.slice(0, -1));
  };

  const toggleIndicator = (key: keyof typeof indicators) => {
    setIndicators(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const signalPayload = payload.find((p: any) => p.dataKey === 'price' && p.payload.type);
      if (signalPayload) {
        const { type, desc, price } = signalPayload.payload;
        return (
          <div className={`bg-terminal-panel border ${type === 'BUY' ? 'border-terminal-up' : 'border-terminal-down'} p-2 rounded shadow-xl text-xs font-mono z-50`}>
            <div className={`font-bold ${type === 'BUY' ? 'text-terminal-up' : 'text-terminal-down'} mb-1`}>{type} SIGNAL</div>
            <div className="text-terminal-text mb-1">{desc}</div>
            <div className="text-terminal-muted">Trigger Price: <span className="text-terminal-text">{price.toFixed(2)}</span></div>
            <div className="text-terminal-muted">Time: <span className="text-terminal-text">{label}</span></div>
          </div>
        )
      }
      const main = payload[0].payload;
      const priceChange = main.close - main.open;
      const isUp = priceChange >= 0;
      return (
        <div className="bg-terminal-panel/95 backdrop-blur border border-terminal-border p-3 rounded shadow-2xl text-xs font-mono z-50 min-w-[180px]">
          <div className="flex justify-between items-center mb-2 border-b border-terminal-border pb-1">
             <span className="text-terminal-muted">{label}</span>
             <span className={isUp ? 'text-terminal-up' : 'text-terminal-down'}>{isUp ? '▲' : '▼'} {Math.abs(priceChange).toFixed(2)}</span>
          </div>
          <div className="grid grid-cols-2 gap-x-4 gap-y-1">
            <span className="text-terminal-muted">Open:</span> <span className="text-right text-terminal-text">{main.open.toFixed(2)}</span>
            <span className="text-terminal-muted">High:</span> <span className="text-right text-terminal-text">{main.high.toFixed(2)}</span>
            <span className="text-terminal-muted">Low:</span> <span className="text-right text-terminal-text">{main.low.toFixed(2)}</span>
            <span className="text-terminal-muted">Close:</span> <span className="text-right text-terminal-text">{main.close.toFixed(2)}</span>
          </div>
        </div>
      );
    }
    return null;
  };

  const RenderSignalShape = (props: any) => {
    const { cx, cy, payload } = props;
    if (payload.type === 'BUY') {
      return (<svg x={cx - 6} y={cy - 6} width={12} height={12} viewBox="0 0 24 24" fill="var(--color-up)" stroke="var(--color-up)" strokeWidth="2"><path d="M12 2L2 22h20L12 2z" /></svg>);
    }
    return (<svg x={cx - 6} y={cy - 6} width={12} height={12} viewBox="0 0 24 24" fill="var(--color-down)" stroke="var(--color-down)" strokeWidth="2"><path d="M12 22L22 2H2L12 22z" /></svg>);
  };

  return (
    <Card 
      title={`Price Action - ${symbol}`} 
      className="h-full flex flex-col relative group"
      actions={
        <div className="flex items-center space-x-3">
           <div className="flex items-center border border-terminal-border rounded overflow-hidden">
              {[TimeFrame.M1, TimeFrame.M5, TimeFrame.H1, TimeFrame.D1].map((tf) => (
                <button key={tf} onClick={() => setTimeframe(tf)} className={`px-2 py-0.5 text-[10px] font-mono transition-colors ${timeframe === tf ? 'bg-terminal-accent text-white font-bold' : 'bg-terminal-panel text-terminal-muted hover:text-terminal-text'}`}>{tf}</button>
              ))}
           </div>
           <div className="h-4 w-px bg-terminal-border"></div>
           <button onClick={() => setShowToolbar(!showToolbar)} className={`p-1 rounded transition-colors ${showToolbar ? 'text-terminal-accent bg-terminal-accent/10' : 'text-terminal-muted hover:text-terminal-text'}`} title="Toggle Drawing Tools"><PenTool size={14} /></button>
           <button onClick={() => setShowComparison(!showComparison)} className={`p-1 rounded transition-colors ${showComparison ? 'text-yellow-400 bg-yellow-400/10' : 'text-terminal-muted hover:text-terminal-text'}`} title="Compare with Market"><Layers size={14} /></button>
           <div className="hidden xl:flex items-center space-x-1">
             <Activity size={12} className="text-terminal-muted mr-1" />
             {(['sma', 'ema', 'rsi', 'macd', 'signals'] as const).map((ind) => (
               <button key={ind} onClick={() => toggleIndicator(ind)} className={`px-1.5 py-0.5 text-[10px] rounded uppercase font-mono transition-all ${indicators[ind] ? 'bg-terminal-accent/20 text-terminal-accent border border-terminal-accent/30' : 'text-terminal-muted hover:text-terminal-text hover:bg-black/5 dark:hover:bg-white/5'}`}>{ind}</button>
             ))}
          </div>
        </div>
      }
    >
      <div className="flex flex-col h-full bg-terminal-bg relative select-none transition-colors duration-200">

        {showToolbar && (
          <div className="absolute left-2 top-2 z-20 flex flex-col gap-1 bg-terminal-panel border border-terminal-border rounded shadow-xl p-1 animate-in slide-in-from-left-2 duration-200">
             <button title="Cursor" onClick={() => setTool('cursor')} className={`p-2 rounded ${tool === 'cursor' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><MousePointer2 size={16} /></button>
             <button title="Trendline" onClick={() => setTool('line')} className={`p-2 rounded ${tool === 'line' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><Pencil size={16} /></button>
             <button title="Box / Zone" onClick={() => setTool('box')} className={`p-2 rounded ${tool === 'box' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><Square size={16} /></button>
             <div className="h-px bg-terminal-border my-1"></div>
             <button title="Undo Last" onClick={handleUndo} className="p-2 rounded text-terminal-muted hover:text-terminal-text hover:bg-terminal-bg"><Undo2 size={16} /></button>
             <button title="Clear All" onClick={() => setDrawings([])} className="p-2 rounded text-red-400 hover:bg-red-500/20"><Trash2 size={16} /></button>
          </div>
        )}

        <div className="absolute top-4 left-14 z-10 flex flex-col pointer-events-none">
          <div className="flex items-baseline space-x-2">
            <h2 className="text-3xl font-bold text-terminal-text font-mono tracking-tighter">{symbol}</h2>
            <span className="text-lg font-medium text-terminal-muted">{timeframe}</span>
          </div>
          {fullChartData.length > 0 && viewState.end < fullChartData.length && (
            <div className={`flex items-center space-x-2 text-sm font-mono mt-1 ${fullChartData[viewState.end].close >= fullChartData[viewState.end].open ? 'text-terminal-up' : 'text-terminal-down'}`}>
               <span className="font-bold">{fullChartData[viewState.end].close.toFixed(2)}</span>
               <span>{fullChartData[viewState.end].close >= fullChartData[viewState.end].open ? '+' : ''}{(fullChartData[viewState.end].close - fullChartData[viewState.end].open).toFixed(2)}</span>
            </div>
          )}
        </div>

        <div className="flex-1 min-h-0 relative" ref={chartRef} onWheel={handleWheel}>
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart 
              data={fullChartData} 
              margin={{ top: 20, right: 60, left: 10, bottom: 5 }}
              onMouseDown={handleMouseDown}
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              onMouseLeave={handleMouseUp}
              style={{ cursor: tool === 'cursor' ? (isDragging ? 'grabbing' : 'grab') : 'crosshair' }}
            >
              <defs>
                <linearGradient id="volGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={theme === 'dark' ? '#333' : '#9ca3af'} stopOpacity={0.8}/>
                  <stop offset="95%" stopColor={theme === 'dark' ? '#333' : '#9ca3af'} stopOpacity={0.1}/>
                </linearGradient>
              </defs>
              <CartesianGrid stroke={gridColor} strokeDasharray="3 3" vertical={true} horizontal={true} />
              <XAxis dataKey="time" tick={{ fontSize: 10, fill: axisColor, fontFamily: 'JetBrains Mono' }} axisLine={{ stroke: gridColor }} tickLine={false} minTickGap={50} />
              <YAxis yAxisId="price" domain={yDomain} orientation="right" tick={{ fontSize: 10, fill: axisColor, fontFamily: 'JetBrains Mono' }} axisLine={false} tickLine={{ stroke: gridColor }} tickFormatter={(val) => val.toFixed(2)} width={50} mirror={false} />
              <YAxis yAxisId="volume" orientation="left" domain={[0, 'dataMax * 4']} hide />
              {showComparison && <YAxis yAxisId="compare" domain={compareDomain} orientation="left" hide={true} />}
              <Tooltip content={<CustomTooltip />} cursor={{ stroke: textColor, strokeWidth: 1, strokeDasharray: '4 4', opacity: 0.5 }} isAnimationActive={false} />
              <Brush dataKey="time" height={20} stroke={brushStroke} fill={brushFill} tickFormatter={() => ''} startIndex={viewState.start} endIndex={viewState.end} onChange={handleBrushChange} />
              <Bar dataKey="volume" yAxisId="volume" fill="url(#volGradient)" barSize={5} isAnimationActive={false} />
              <Bar dataKey={(d) => [d.low, d.high]} yAxisId="price" barSize={1} fill="#fff" isAnimationActive={false}>
                 {fullChartData.map((entry, index) => (<Cell key={`wick-${index}`} fill={entry.close >= entry.open ? 'var(--color-up)' : 'var(--color-down)'} />))}
              </Bar>
              <Bar dataKey={(d) => [Math.min(d.open, d.close), Math.max(d.open, d.close)]} yAxisId="price" barSize={8} isAnimationActive={false}>
                 {fullChartData.map((entry, index) => (<Cell key={`body-${index}`} fill={entry.close >= entry.open ? 'var(--color-up)' : 'var(--color-down)'} />))}
              </Bar>
              {showComparison && <Line yAxisId="compare" type="monotone" dataKey="comparePrice" stroke="#facc15" strokeWidth={2} dot={false} isAnimationActive={false} />}
              {indicators.sma && <Line yAxisId="price" type="monotone" dataKey="sma20" stroke="#fb923c" strokeWidth={1} dot={false} isAnimationActive={false} />}
              {indicators.ema && <Line yAxisId="price" type="monotone" dataKey="ema" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />}
              {indicators.signals && (
                <>
                  <Line yAxisId="price" type="monotone" dataKey="sma50" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} strokeOpacity={0.6} />
                  <Line yAxisId="price" type="monotone" dataKey="sma200" stroke="#a855f7" strokeWidth={1} dot={false} isAnimationActive={false} strokeOpacity={0.6} />
                  <Scatter yAxisId="price" data={signalData} shape={<RenderSignalShape />} isAnimationActive={false} />
                </>
              )}
              {drawings.map((d) => (
                d.type === 'line' 
                  ? <ReferenceLine yAxisId="price" key={d.id} segment={[{ x: d.startX, y: d.startY }, { x: d.endX, y: d.endY }]} stroke="#eab308" strokeWidth={2} />
                  : <ReferenceArea yAxisId="price" key={d.id} x1={d.startX} x2={d.endX} y1={d.startY} y2={d.endY} fill="#eab308" fillOpacity={0.2} stroke="#eab308" />
              ))}
              {currentDrawing && currentDrawing.endX && (
                 currentDrawing.type === 'line'
                 ? <ReferenceLine yAxisId="price" segment={[{ x: currentDrawing.startX!, y: currentDrawing.startY! }, { x: currentDrawing.endX, y: currentDrawing.endY }]} stroke="#eab308" strokeWidth={2} strokeDasharray="3 3" />
