                 <CartesianGrid stroke={gridColor} strokeDasharray="3 3" vertical={false} />
                 <YAxis orientation="right" tick={{ fontSize: 9, fill: axisColor }} axisLine={false} tickLine={false} width={50} />
                 <Tooltip content={<CustomTooltip />} cursor={{ stroke: textColor, strokeDasharray: '4 4' }} />
                 <ReferenceLine y={0} stroke={axisColor} />
                 <Bar dataKey="macdHistogram" fill="#444" isAnimationActive={false}>
                    {fullChartData.slice(viewState.start, viewState.end + 1).map((entry, index) => (
