import { CommandPalette } from './components/CommandPalette';
import { PortfolioWidget } from './components/PortfolioWidget';
import { AIAssistant } from './components/AIAssistant';
import { marketService } from './services/marketService';
import { portfolioService } from './services/portfolioService';
import { Quote } from './types';

function App() {
  const [activeTab, setActiveTab] = useState<'trade' | 'research'>('trade');
  const [selectedSymbol, setSelectedSymbol] = useState<string>('AAPL');
  const [selectedQuote, setSelectedQuote] = useState<Quote | undefined>(undefined);
  const [isCommandOpen, setIsCommandOpen] = useState(false);
  const [isPaper, setIsPaper] = useState(true);
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  // Theme Management
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  // Sync selected quote with real-time updates
  useEffect(() => {
    const unsubscribe = marketService.subscribe((quotes) => {
      const quote = quotes.find(q => q.symbol === selectedSymbol);
      if (quote) {
        setSelectedQuote(quote);
      }
    });
    return unsubscribe;
  }, [selectedSymbol]);

  // Sync portfolio mode
  useEffect(() => {
    const unsubscribe = portfolioService.subscribeMode(setIsPaper);
    return unsubscribe;
  }, []);

  // Global Key Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsCommandOpen(true);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  return (
    <div className="flex flex-col h-screen bg-terminal-bg text-terminal-text font-sans selection:bg-terminal-accent selection:text-black overflow-hidden transition-colors duration-200">

      <Header 
        onOpenCommand={() => setIsCommandOpen(true)} 
        isPaper={isPaper}
        onToggleMode={() => portfolioService.toggleMode()}
        activeTab={activeTab}
        onTabChange={setActiveTab}
        theme={theme}
        onToggleTheme={toggleTheme}
      />

      {/* Main Page Layout */}
      <main className="flex-1 overflow-hidden relative p-1">

        {/* ================= TRADE VIEW ================= */}
        {activeTab === 'trade' && (
          <div className="flex flex-col lg:flex-row h-full w-full gap-1 animate-in fade-in duration-300">

            {/* LEFT COLUMN: Execution & Market Data (25%) */}
            <div className="w-full lg:w-[25%] flex flex-col gap-1 h-full min-w-[300px]">

              {/* Order Ticket (Fixed Height) */}
              <div className="h-auto min-h-[320px] shrink-0">
                <OrderTicket quote={selectedQuote} />
              </div>

              {/* Quote Grid (Fills remaining) */}
              <div className="flex-1 min-h-0">
                <QuoteGrid 
                  onSelectSymbol={setSelectedSymbol} 
                  selectedSymbol={selectedSymbol} 
                />
              </div>
            </div>

            {/* RIGHT COLUMN: Charting (75%) */}
            <div className="flex-1 h-full min-w-0">
              <ChartWidget symbol={selectedSymbol} theme={theme} />
            </div>

          </div>
        )}

        {/* ================= RESEARCH VIEW ================= */}
        {activeTab === 'research' && (
          <div className="flex flex-col lg:flex-row h-full w-full gap-1 animate-in fade-in duration-300">

            {/* LEFT COLUMN: Portfolio & Holdings (30%) */}
            <div className="w-full lg:w-[30%] h-full min-h-0">
               <PortfolioWidget />
            </div>

            {/* CENTER COLUMN: AI Assistant (40%) */}
            <div className="w-full lg:w-[40%] h-full min-h-0">
              <AIAssistant theme={theme} />
            </div>

            {/* RIGHT COLUMN: Analysis Tools (30%) */}
            <div className="w-full lg:w-[30%] h-full flex flex-col gap-1 min-h-0">

              {/* Top: AI Prediction */}
              <div className="flex-1 min-h-0">
                <PredictionWidget symbol={selectedSymbol} theme={theme} />
              </div>

              {/* Bottom: News Feed */}
              <div className="flex-1 min-h-0">
                <NewsFeed />
              </div>

            </div>
          </div>
        )}

      </main>

      {/* Command Palette Modal */}
      <CommandPalette 
        isOpen={isCommandOpen} 
        onClose={() => setIsCommandOpen(false)}
        onSelect={setSelectedSymbol}
      />
    </div>
  );
}

