interface ChartWidgetProps {
  symbol: string;
  theme?: 'dark' | 'light';
}

interface Drawing {
  id: string;
  type: 'line' | 'box';
  startX: string; // Time label
  startY: number; // Price
  endX: string;
  endY: number;
}

type ToolType = 'cursor' | 'line' | 'box';

interface Signal {
  time: string;
  price: number;
  type: 'BUY' | 'SELL' | 'PATTERN';
  desc: string;
  patternName?: string;
}

// --- Indicator Helpers ---
const calculateSMA = (data: any[], period: number) => {
  return data.map((item, index, arr) => {
    if (index < period - 1) return { ...item, [`sma${period}`]: null };
    const slice = arr.slice(index - period + 1, index + 1);
    const sum = slice.reduce((acc, curr) => acc + curr.close, 0);
    return { ...item, [`sma${period}`]: sum / period };
  });
};

const calculateEMA = (data: any[], period: number) => {
  const k = 2 / (period + 1);
  let ema = data[0].close;
  return data.map((item, index) => {
    if (index === 0) return { ...item, ema: item.close };
    ema = (item.close - ema) * k + ema;
    return { ...item, ema };
  });
};

const calculateRSI = (data: any[], period: number = 14) => {
  let gains = 0;
  let losses = 0;
  for (let i = 1; i <= period; i++) {
    const change = data[i].close - data[i - 1].close;
    if (change > 0) gains += change;
    else losses -= change;
  }
  let avgGain = gains / period;
  let avgLoss = losses / period;

  return data.map((item, index) => {
    if (index < period) return { ...item, rsi: null };
    if (index > period) {
      const change = item.close - data[index - 1].close;
      const gain = change > 0 ? change : 0;
      const loss = change < 0 ? -change : 0;
      avgGain = (avgGain * (period - 1) + gain) / period;
      avgLoss = (avgLoss * (period - 1) + loss) / period;
    }
    const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    const rsi = 100 - (100 / (1 + rs));
    return { ...item, rsi };
  });
};

const calculateMACD = (data: any[]) => {
  const ema12Data = calculateEMA(data, 12);
  const ema26Data = calculateEMA(data, 26);
  const macdData = data.map((item, i) => {
    const ema12 = ema12Data[i].ema;
    const ema26 = ema26Data[i].ema;
    return { ...item, macdLine: (ema12 && ema26) ? ema12 - ema26 : null };
  });
  const period = 9;
  const k = 2 / (period + 1);
  let signal = 0;
  let firstValidIndex = -1;
  return macdData.map((item, i) => {
    if (item.macdLine === null) return { ...item, macdSignal: null, macdHistogram: null };
    if (firstValidIndex === -1) {
      firstValidIndex = i;
      signal = item.macdLine;
      return { ...item, macdSignal: signal, macdHistogram: 0 };
    }
    signal = (item.macdLine - signal) * k + signal;
    return { ...item, macdSignal: signal, macdHistogram: item.macdLine - signal };
  });
};

// Enhanced Analysis with Tweezer Detection
const detectCandlestickPatterns = (data: any[]): Signal[] => {
  const signals: Signal[] = [];
  const epsilon = 0.05; // Tolerance for "equal" highs/lows

  for (let i = 1; i < data.length; i++) {
    const prev = data[i-1];
    const curr = data[i];

    // MA Crossover Logic
    if (prev.sma50 && prev.sma200 && curr.sma50 && curr.sma200) {
      if (prev.sma50 <= prev.sma200 && curr.sma50 > curr.sma200) {
        signals.push({ time: curr.time, price: curr.low * 0.995, type: 'BUY', desc: 'Golden Cross' });
      } else if (prev.sma50 >= prev.sma200 && curr.sma50 < curr.sma200) {
        signals.push({ time: curr.time, price: curr.high * 1.005, type: 'SELL', desc: 'Death Cross' });
      }
    }

    // Tweezer Top Detection
    // 1. Previous candle Bullish (Close > Open)
    // 2. Current candle Bearish (Close < Open)
    // 3. Highs are equal (within epsilon)
    const prevBull = prev.close > prev.open;
    const currBear = curr.close < curr.open;
    const matchingHighs = Math.abs(prev.high - curr.high) < (prev.high * 0.0005); // 0.05% tolerance

    if (prevBull && currBear && matchingHighs) {
      signals.push({ 
        time: curr.time, 
        price: curr.high + (curr.high * 0.002), 
        type: 'PATTERN', 
        desc: 'Potential Reversal Down',
        patternName: 'TWZ TOP'
      });
    }

    // Tweezer Bottom Detection
    // 1. Previous candle Bearish
    // 2. Current candle Bullish
    // 3. Lows are equal
    const prevBear = prev.close < prev.open;
    const currBull = curr.close > curr.open;
    const matchingLows = Math.abs(prev.low - curr.low) < (prev.low * 0.0005);

    if (prevBear && currBull && matchingLows) {
      signals.push({ 
        time: curr.time, 
        price: curr.low - (curr.low * 0.002), 
        type: 'PATTERN', 
        desc: 'Potential Reversal Up',
        patternName: 'TWZ BOT'
      });
    }
  }
  return signals;
};

export const ChartWidget: React.FC<ChartWidgetProps> = ({ symbol, theme = 'dark' }) => {
  // Data State
  const [rawData, setRawData] = useState<any[]>([]);
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.M5);

  // View State (Zoom/Pan)
  const [viewState, setViewState] = useState({ start: 0, end: 100 }); 
  const MIN_ZOOM = 20; 
  const DEFAULT_ZOOM = 80; // Slightly closer zoom for pattern visibility

  // UI State
  const [indicators, setIndicators] = useState({ sma: false, ema: false, rsi: false, macd: false, signals: true });
  const [showComparison, setShowComparison] = useState(false);
  const [showToolbar, setShowToolbar] = useState(false);

  // Drawing State
  const [tool, setTool] = useState<ToolType>('cursor');
  const [drawings, setDrawings] = useState<Drawing[]>([]);
  const [currentDrawing, setCurrentDrawing] = useState<Partial<Drawing> | null>(null);

  // Interaction State
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState<number | null>(null); 

  const chartRef = useRef<HTMLDivElement>(null);

  // Theme constants
  const axisColor = theme === 'dark' ? '#555' : '#9ca3af';
  const gridColor = theme === 'dark' ? '#1a1a1a' : '#e5e7eb';
  const brushStroke = theme === 'dark' ? '#333' : '#d1d5db';
  const brushFill = theme === 'dark' ? '#0a0a0a' : '#f9fafb';
  const textColor = theme === 'dark' ? '#e5e5e5' : '#1f2937';

  // Initialize Data
  useEffect(() => {
    const totalPoints = 500;
    const newData = generateChartData(totalPoints);
    setRawData(newData);
    setViewState({ start: totalPoints - DEFAULT_ZOOM, end: totalPoints - 1 });
    setDrawings([]);
    setCurrentDrawing(null);
  }, [symbol, timeframe]);

  // Process Indicators & Comparison
  const fullChartData = useMemo(() => {
    if (!rawData.length) return [];
    let processed = [...rawData];
    processed = calculateSMA(processed, 50);
    processed = calculateSMA(processed, 200);
    if (indicators.sma) processed = calculateSMA(processed, 20);
    if (indicators.ema) processed = calculateEMA(processed, 20);
    if (indicators.rsi) processed = calculateRSI(processed, 14);
    if (indicators.macd) processed = calculateMACD(processed);
    return processed;
  }, [rawData, indicators]);

  const signalData = useMemo(() => {
    if (!indicators.signals) return [];
    return detectCandlestickPatterns(fullChartData);
  }, [fullChartData, indicators.signals]);

  const yDomain = useMemo(() => {
    if (!fullChartData.length) return [0, 0];
    const visibleSlice = fullChartData.slice(viewState.start, viewState.end + 1);
    if (!visibleSlice.length) return [0, 0];
    const highs = visibleSlice.map(d => d.high);
    const lows = visibleSlice.map(d => d.low);
    const min = Math.min(...lows);
    const max = Math.max(...highs);
    const padding = (max - min) * 0.1;
    return [min - padding, max + padding];
  }, [fullChartData, viewState]);

  const compareDomain = useMemo(() => {
    if (!showComparison || !fullChartData.length) return [0, 0];
    const visibleSlice = fullChartData.slice(viewState.start, viewState.end + 1);
    const prices = visibleSlice.map(d => d.comparePrice);
    const min = Math.min(...prices);
    const max = Math.max(...prices);
    const padding = (max - min) * 0.1;
    return [min - padding, max + padding];
  }, [fullChartData, showComparison, viewState]);

  const handleBrushChange = (e: any) => {
    if (e.startIndex !== undefined && e.endIndex !== undefined) {
      setViewState({ start: e.startIndex, end: e.endIndex });
    }
  };

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    if (tool !== 'cursor') return;
    const zoomSpeed = 0.5;
    const delta = Math.sign(e.deltaY) * Math.round(Math.abs(e.deltaY) * zoomSpeed);
    setViewState(prev => {
      const currentLength = prev.end - prev.start;
      let newLength = currentLength + delta;
      if (newLength < MIN_ZOOM) newLength = MIN_ZOOM;
      if (newLength > fullChartData.length) newLength = fullChartData.length;
      const center = prev.start + currentLength / 2;
      let newStart = center - newLength / 2;
      let newEnd = center + newLength / 2;
      if (newEnd >= fullChartData.length) { newEnd = fullChartData.length - 1; newStart = newEnd - newLength; }
      if (newStart < 0) { newStart = 0; newEnd = newLength; }
      return { start: Math.round(newStart), end: Math.round(newEnd) };
    });
  };

  const getPriceFromY = (chartY: number, height: number) => {
    const [min, max] = yDomain;
    if (min === max) return min;
    const top = 20; const bottom = 40; 
    const chartHeight = height - top - bottom;
    if (chartHeight <= 0) return 0;
    const relativeY = chartY - top;
    const ratio = Math.max(0, Math.min(1, relativeY / chartHeight));
    const priceRange = max - min;
    return max - (ratio * priceRange);
  };

  const handleMouseDown = (e: any) => {
    if (!e) return;
    if (tool === 'cursor') { setIsDragging(true); setDragStart(e.chartX); return; }
    if (e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing({ id: Date.now().toString(), type: tool === 'line' ? 'line' : 'box', startX: e.activeLabel, startY: price, endX: e.activeLabel, endY: price });
    }
  };

  const handleMouseMove = (e: any) => {
    if (!e) return;
    if (isDragging && tool === 'cursor' && dragStart !== null && e.chartX) { return; }
    if (currentDrawing && e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing(prev => ({ ...prev, endX: e.activeLabel, endY: price }));
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false); setDragStart(null);
    if (currentDrawing && currentDrawing.endX && currentDrawing.endY) {
      setDrawings(prev => [...prev, currentDrawing as Drawing]);
      setCurrentDrawing(null);
    }
  };

  const handleUndo = () => {
    setDrawings(prev => prev.slice(0, -1));
  };

  const toggleIndicator = (key: keyof typeof indicators) => {
    setIndicators(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const signalPayload = payload.find((p: any) => p.dataKey === 'price' && p.payload.type);
      if (signalPayload) {
        const { type, desc, price, patternName } = signalPayload.payload;
        return (
          <div className={`bg-terminal-panel border ${type === 'BUY' || patternName?.includes('BOT') ? 'border-terminal-up' : 'border-terminal-down'} p-2 rounded shadow-xl text-xs font-mono z-50`}>
            <div className={`font-bold ${type === 'BUY' || patternName?.includes('BOT') ? 'text-terminal-up' : 'text-terminal-down'} mb-1`}>{patternName || type} SIGNAL</div>
            <div className="text-terminal-text mb-1">{desc}</div>
            <div className="text-terminal-muted">Price: <span className="text-terminal-text">{price.toFixed(2)}</span></div>
            <div className="text-terminal-muted">Time: <span className="text-terminal-text">{label}</span></div>
          </div>
        )
      }
      const main = payload[0].payload;
      const priceChange = main.close - main.open;
      const isUp = priceChange >= 0;
      return (
        <div className="bg-terminal-panel/95 backdrop-blur border border-terminal-border p-3 rounded shadow-2xl text-xs font-mono z-50 min-w-[180px]">
          <div className="flex justify-between items-center mb-2 border-b border-terminal-border pb-1">
             <span className="text-terminal-muted">{label}</span>
             <span className={isUp ? 'text-terminal-up' : 'text-terminal-down'}>{isUp ? '▲' : '▼'} {Math.abs(priceChange).toFixed(2)}</span>
          </div>
          <div className="grid grid-cols-2 gap-x-4 gap-y-1">
            <span className="text-terminal-muted">Open:</span> <span className="text-right text-terminal-text">{main.open.toFixed(2)}</span>
            <span className="text-terminal-muted">High:</span> <span className="text-right text-terminal-text">{main.high.toFixed(2)}</span>
            <span className="text-terminal-muted">Low:</span> <span className="text-right text-terminal-text">{main.low.toFixed(2)}</span>
            <span className="text-terminal-muted">Close:</span> <span className="text-right text-terminal-text">{main.close.toFixed(2)}</span>
          </div>
        </div>
      );
    }
    return null;
  };

  const RenderSignalShape = (props: any) => {
    const { cx, cy, payload } = props;
    if (payload.type === 'PATTERN') {
      const isTop = payload.patternName === 'TWZ TOP';
      return (
        <g>
          <text x={cx} y={isTop ? cy - 10 : cy + 15} textAnchor="middle" fill={isTop ? 'var(--color-down)' : 'var(--color-up)'} fontSize={8} fontWeight="bold">
            {payload.patternName}
          </text>
          <circle cx={cx} cy={cy} r={3} fill={isTop ? 'var(--color-down)' : 'var(--color-up)'} />
        </g>
      );
    }
    if (payload.type === 'BUY') {
      return (<svg x={cx - 6} y={cy - 6} width={12} height={12} viewBox="0 0 24 24" fill="var(--color-up)" stroke="var(--color-up)" strokeWidth="2"><path d="M12 2L2 22h20L12 2z" /></svg>);
    }
    return (<svg x={cx - 6} y={cy - 6} width={12} height={12} viewBox="0 0 24 24" fill="var(--color-down)" stroke="var(--color-down)" strokeWidth="2"><path d="M12 22L22 2H2L12 22z" /></svg>);
  };

  return (
    <Card 
      title={`Price Action - ${symbol}`} 
      className="h-full flex flex-col relative group"
      actions={
        <div className="flex items-center space-x-3">
           <div className="flex items-center border border-terminal-border rounded overflow-hidden">
              {[TimeFrame.M1, TimeFrame.M5, TimeFrame.H1, TimeFrame.D1].map((tf) => (
                <button key={tf} onClick={() => setTimeframe(tf)} className={`px-2 py-0.5 text-[10px] font-mono transition-colors ${timeframe === tf ? 'bg-terminal-accent text-white font-bold' : 'bg-terminal-panel text-terminal-muted hover:text-terminal-text'}`}>{tf}</button>
              ))}
           </div>
           <div className="h-4 w-px bg-terminal-border"></div>
           <button onClick={() => setShowToolbar(!showToolbar)} className={`p-1 rounded transition-colors ${showToolbar ? 'text-terminal-accent bg-terminal-accent/10' : 'text-terminal-muted hover:text-terminal-text'}`} title="Toggle Drawing Tools"><PenTool size={14} /></button>
           <button onClick={() => setShowComparison(!showComparison)} className={`p-1 rounded transition-colors ${showComparison ? 'text-yellow-400 bg-yellow-400/10' : 'text-terminal-muted hover:text-terminal-text'}`} title="Compare with Market"><Layers size={14} /></button>
           <div className="hidden xl:flex items-center space-x-1">
             <Activity size={12} className="text-terminal-muted mr-1" />
             {(['sma', 'ema', 'rsi', 'macd', 'signals'] as const).map((ind) => (
               <button key={ind} onClick={() => toggleIndicator(ind)} className={`px-1.5 py-0.5 text-[10px] rounded uppercase font-mono transition-all ${indicators[ind] ? 'bg-terminal-accent/20 text-terminal-accent border border-terminal-accent/30' : 'text-terminal-muted hover:text-terminal-text hover:bg-black/5 dark:hover:bg-white/5'}`}>{ind}</button>
             ))}
          </div>
        </div>
      }
    >
      <div className="flex flex-col h-full bg-terminal-bg relative select-none transition-colors duration-200">

        {showToolbar && (
          <div className="absolute left-2 top-2 z-20 flex flex-col gap-1 bg-terminal-panel border border-terminal-border rounded shadow-xl p-1 animate-in slide-in-from-left-2 duration-200">
             <button title="Cursor" onClick={() => setTool('cursor')} className={`p-2 rounded ${tool === 'cursor' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><MousePointer2 size={16} /></button>
             <button title="Trendline" onClick={() => setTool('line')} className={`p-2 rounded ${tool === 'line' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><Pencil size={16} /></button>
             <button title="Box / Zone" onClick={() => setTool('box')} className={`p-2 rounded ${tool === 'box' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><Square size={16} /></button>
             <div className="h-px bg-terminal-border my-1"></div>
             <button title="Undo Last" onClick={handleUndo} className="p-2 rounded text-terminal-muted hover:text-terminal-text hover:bg-terminal-bg"><Undo2 size={16} /></button>
             <button title="Clear All" onClick={() => setDrawings([])} className="p-2 rounded text-red-400 hover:bg-red-500/20"><Trash2 size={16} /></button>
          </div>
        )}

        <div className="absolute top-4 left-14 z-10 flex flex-col pointer-events-none">
          <div className="flex items-baseline space-x-2">
            <h2 className="text-3xl font-bold text-terminal-text font-mono tracking-tighter">{symbol}</h2>
            <span className="text-lg font-medium text-terminal-muted">{timeframe}</span>
          </div>
          {fullChartData.length > 0 && viewState.end < fullChartData.length && (
            <div className={`flex items-center space-x-2 text-sm font-mono mt-1 ${fullChartData[viewState.end].close >= fullChartData[viewState.end].open ? 'text-terminal-up' : 'text-terminal-down'}`}>
               <span className="font-bold">{fullChartData[viewState.end].close.toFixed(2)}</span>
               <span>{fullChartData[viewState.end].close >= fullChartData[viewState.end].open ? '+' : ''}{(fullChartData[viewState.end].close - fullChartData[viewState.end].open).toFixed(2)}</span>
            </div>
          )}
        </div>

        <div className="flex-1 min-h-0 relative" ref={chartRef} onWheel={handleWheel}>
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart 
              data={fullChartData} 
              margin={{ top: 20, right: 60, left: 10, bottom: 5 }}
              onMouseDown={handleMouseDown}
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              onMouseLeave={handleMouseUp}
              style={{ cursor: tool === 'cursor' ? (isDragging ? 'grabbing' : 'grab') : 'crosshair' }}
            >
              <defs>
                <linearGradient id="volGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={theme === 'dark' ? '#333' : '#9ca3af'} stopOpacity={0.8}/>
                  <stop offset="95%" stopColor={theme === 'dark' ? '#333' : '#9ca3af'} stopOpacity={0.1}/>
                </linearGradient>
              </defs>
              <CartesianGrid stroke={gridColor} strokeDasharray="3 3" vertical={true} horizontal={true} />
              <XAxis dataKey="time" tick={{ fontSize: 10, fill: axisColor, fontFamily: 'JetBrains Mono' }} axisLine={{ stroke: gridColor }} tickLine={false} minTickGap={50} />
              <YAxis yAxisId="price" domain={yDomain} orientation="right" tick={{ fontSize: 10, fill: axisColor, fontFamily: 'JetBrains Mono' }} axisLine={false} tickLine={{ stroke: gridColor }} tickFormatter={(val) => val.toFixed(2)} width={50} mirror={false} />
              <YAxis yAxisId="volume" orientation="left" domain={[0, 'dataMax * 4']} hide />
              {showComparison && <YAxis yAxisId="compare" domain={compareDomain} orientation="left" hide={true} />}
              <Tooltip content={<CustomTooltip />} cursor={{ stroke: textColor, strokeWidth: 1, strokeDasharray: '4 4', opacity: 0.5 }} isAnimationActive={false} />
              <Brush dataKey="time" height={20} stroke={brushStroke} fill={brushFill} tickFormatter={() => ''} startIndex={viewState.start} endIndex={viewState.end} onChange={handleBrushChange} />
              <Bar dataKey="volume" yAxisId="volume" fill="url(#volGradient)" barSize={5} isAnimationActive={false} />

              {/* Candlestick Wicks (Thin Line) */}
              <Bar dataKey={(d) => [d.low, d.high]} yAxisId="price" barSize={1} isAnimationActive={false}>
                 {fullChartData.map((entry, index) => (<Cell key={`wick-${index}`} fill={entry.close >= entry.open ? 'var(--color-up)' : 'var(--color-down)'} />))}
              </Bar>

              {/* Candlestick Body (Thicker Bar) */}
              <Bar dataKey={(d) => [Math.min(d.open, d.close), Math.max(d.open, d.close)]} yAxisId="price" barSize={7} isAnimationActive={false}>
                 {fullChartData.map((entry, index) => (<Cell key={`body-${index}`} fill={entry.close >= entry.open ? 'var(--color-up)' : 'var(--color-down)'} />))}
              </Bar>

              {showComparison && <Line yAxisId="compare" type="monotone" dataKey="comparePrice" stroke="#facc15" strokeWidth={2} dot={false} isAnimationActive={false} />}
              {indicators.sma && <Line yAxisId="price" type="monotone" dataKey="sma20" stroke="#fb923c" strokeWidth={1} dot={false} isAnimationActive={false} />}
              {indicators.ema && <Line yAxisId="price" type="monotone" dataKey="ema" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />}
              {indicators.signals && (
                <>
                  <Line yAxisId="price" type="monotone" dataKey="sma50" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} strokeOpacity={0.6} />
                  <Line yAxisId="price" type="monotone" dataKey="sma200" stroke="#a855f7" strokeWidth={1} dot={false} isAnimationActive={false} strokeOpacity={0.6} />
                  <Scatter yAxisId="price" data={signalData} shape={<RenderSignalShape />} isAnimationActive={false} />
                </>
              )}
              {drawings.map((d) => (
                d.type === 'line' 
                  ? <ReferenceLine yAxisId="price" key={d.id} segment={[{ x: d.startX, y: d.startY }, { x: d.endX, y: d.endY }]} stroke="#eab308" strokeWidth={2} />
                  : <ReferenceArea yAxisId="price" key={d.id} x1={d.startX} x2={d.endX} y1={d.startY} y2={d.endY} fill="#eab308" fillOpacity={0.2} stroke="#eab308" />
              ))}
              {currentDrawing && currentDrawing.endX && (
                 currentDrawing.type === 'line'
                 ? <ReferenceLine yAxisId="price" segment={[{ x: currentDrawing.startX!, y: currentDrawing.startY! }, { x: currentDrawing.endX, y: currentDrawing.endY }]} stroke="#eab308" strokeWidth={2} strokeDasharray="3 3" />
                 : <ReferenceArea yAxisId="price" x1={currentDrawing.startX} x2={currentDrawing.endX} y1={currentDrawing.startY} y2={currentDrawing.endY} fill="#eab308" fillOpacity={0.1} stroke="#eab308" strokeDasharray="3 3" />
              )}
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {indicators.rsi && (
          <div className="h-24 shrink-0 border-t border-terminal-border/50 bg-terminal-bg">
             <ResponsiveContainer width="100%" height="100%">
               <ComposedChart data={fullChartData.slice(viewState.start, viewState.end + 1)} margin={{ top: 5, right: 60, left: 10, bottom: 0 }}>
                 <CartesianGrid stroke={gridColor} strokeDasharray="3 3" vertical={false} />
                 <YAxis domain={[0, 100]} orientation="right" tick={{ fontSize: 9, fill: axisColor }} axisLine={false} tickLine={false} width={50} ticks={[30, 70]} />
                 <Tooltip content={<CustomTooltip />} cursor={{ stroke: textColor, strokeDasharray: '4 4' }} />
                 <ReferenceLine y={70} stroke={axisColor} strokeDasharray="3 3" />
                 <ReferenceLine y={30} stroke={axisColor} strokeDasharray="3 3" />
                 <Line type="monotone" dataKey="rsi" stroke="#c084fc" strokeWidth={1} dot={false} isAnimationActive={false} />
               </ComposedChart>
             </ResponsiveContainer>
          </div>
        )}

        {indicators.macd && (
          <div className="h-24 shrink-0 border-t border-terminal-border/50 bg-terminal-bg">
             <ResponsiveContainer width="100%" height="100%">
               <ComposedChart data={fullChartData.slice(viewState.start, viewState.end + 1)} margin={{ top: 5, right: 60, left: 10, bottom: 0 }}>
                 <CartesianGrid stroke={gridColor} strokeDasharray="3 3" vertical={false} />
                 <YAxis orientation="right" tick={{ fontSize: 9, fill: axisColor }} axisLine={false} tickLine={false} width={50} />
                 <Tooltip content={<CustomTooltip />} cursor={{ stroke: textColor, strokeDasharray: '4 4' }} />
                 <ReferenceLine y={0} stroke={axisColor} />
                 <Bar dataKey="macdHistogram" fill="#444" isAnimationActive={false}>
                    {fullChartData.slice(viewState.start, viewState.end + 1).map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={(entry as any).macdHistogram > 0 ? '#22c55e' : '#ef4444'} />
                    ))}
                 </Bar>
                 <Line type="monotone" dataKey="macdLine" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />
                 <Line type="monotone" dataKey="macdSignal" stroke="#f97316" strokeWidth={1} dot={false} isAnimationActive={false} />
               </ComposedChart>
             </ResponsiveContainer>
          </div>
        )}
      </div>
    </Card>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  ComposedChart, 
  Bar,
  Line, 
  AreaChart, 
  Area,
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  ReferenceLine,
  ReferenceArea,
  Cell,
  Scatter,
  Brush,
} from 'recharts';
import { Card } from './Card';
import { TimeFrame } from '../types';
import { generateChartData } from '../constants';
import { Activity, Pencil, Square, Trash2, MousePointer2, Layers, PenTool, Undo2 } from 'lucide-react';

interface ChartWidgetProps {
  symbol: string;
  theme?: 'dark' | 'light';
}

interface Drawing {
  id: string;
  type: 'line' | 'box';
  startX: string;
  startY: number;
  endX: string;
  endY: number;
}

type ToolType = 'cursor' | 'line' | 'box';

interface Signal {
  time: string;
  price: number;
  type: 'BUY' | 'SELL' | 'PATTERN';
  desc: string;
  patternName?: string;
}

// --- Indicators ---
const calculateSMA = (data: any[], period: number) => {
  return data.map((item, index, arr) => {
    if (index < period - 1) return { ...item, [`sma${period}`]: null };
    const slice = arr.slice(index - period + 1, index + 1);
    const sum = slice.reduce((acc, curr) => acc + curr.close, 0);
    return { ...item, [`sma${period}`]: sum / period };
  });
};

const calculateEMA = (data: any[], period: number) => {
  const k = 2 / (period + 1);
  let ema = data[0].close;
  return data.map((item, index) => {
    if (index === 0) return { ...item, ema: item.close };
    ema = (item.close - ema) * k + ema;
    return { ...item, ema };
  });
};

// --- Pattern Detection ---
const detectCandlestickPatterns = (data: any[]): Signal[] => {
  const signals: Signal[] = [];

  for (let i = 1; i < data.length; i++) {
    const prev = data[i-1];
    const curr = data[i];

    // Tweezer Top: Previous Bullish, Current Bearish, Matching Highs
    const prevBull = prev.close > prev.open;
    const currBear = curr.close < curr.open;
    // Tolerance of 0.05%
    const matchingHighs = Math.abs(prev.high - curr.high) < (prev.high * 0.0005); 

    if (prevBull && currBear && matchingHighs) {
      signals.push({ 
        time: curr.time, 
        price: curr.high, 
        type: 'PATTERN', 
        desc: 'Bearish Reversal',
        patternName: 'TWZ TOP'
      });
    }

    // Tweezer Bottom: Previous Bearish, Current Bullish, Matching Lows
    const prevBear = prev.close < prev.open;
    const currBull = curr.close > curr.open;
    const matchingLows = Math.abs(prev.low - curr.low) < (prev.low * 0.0005);

    if (prevBear && currBull && matchingLows) {
      signals.push({ 
        time: curr.time, 
        price: curr.low, 
        type: 'PATTERN', 
        desc: 'Bullish Reversal',
        patternName: 'TWZ BOT'
      });
    }
  }
  return signals;
};

export const ChartWidget: React.FC<ChartWidgetProps> = ({ symbol, theme = 'dark' }) => {
  // Data State
  const [rawData, setRawData] = useState<any[]>([]);
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.M5);

  // View State (Zoom/Pan)
  // Default to showing the last 80 candles
  const [viewState, setViewState] = useState({ start: 420, end: 499 });

  // UI State
  const [indicators, setIndicators] = useState({ sma: false, ema: false, signals: true });
  const [showToolbar, setShowToolbar] = useState(false);

  // Drawing State
  const [tool, setTool] = useState<ToolType>('cursor');
  const [drawings, setDrawings] = useState<Drawing[]>([]);
  const [currentDrawing, setCurrentDrawing] = useState<Partial<Drawing> | null>(null);

  // Interaction State
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState<number | null>(null); 
  const chartRef = useRef<HTMLDivElement>(null);

  // Constants
  const AXIS_COLOR = theme === 'dark' ? '#555' : '#9ca3af';
  const GRID_COLOR = theme === 'dark' ? '#1a1a1a' : '#e5e7eb';
  const COLOR_UP = '#10b981'; // Green-500 equivalent
  const COLOR_DOWN = '#ef4444'; // Red-500 equivalent

  // Initialize Data
  useEffect(() => {
    const totalPoints = 500;
    const newData = generateChartData(totalPoints);
    setRawData(newData);
    setViewState({ start: totalPoints - 80, end: totalPoints - 1 });
    setDrawings([]);
  }, [symbol, timeframe]);

  // Process Data
  const fullChartData = useMemo(() => {
    if (!rawData.length) return [];
    let processed = [...rawData];
    processed = calculateSMA(processed, 50);
    processed = calculateSMA(processed, 200);
    if (indicators.sma) processed = calculateSMA(processed, 20);
    if (indicators.ema) processed = calculateEMA(processed, 20);
    return processed;
  }, [rawData, indicators]);

  // Derived Data for Display
  // CRITICAL: We slice the data specifically for the main chart to ensure 1:1 mapping with bars/cells
  const visibleData = useMemo(() => {
    if (!fullChartData.length) return [];
    const start = Math.max(0, viewState.start);
    const end = Math.min(fullChartData.length - 1, viewState.end);
    return fullChartData.slice(start, end + 1);
  }, [fullChartData, viewState]);

  const signalData = useMemo(() => {
    if (!indicators.signals) return [];
    return detectCandlestickPatterns(visibleData);
  }, [visibleData, indicators.signals]);

  const yDomain = useMemo(() => {
    if (!visibleData.length) return [0, 0];
    const highs = visibleData.map(d => d.high);
    const lows = visibleData.map(d => d.low);
    const min = Math.min(...lows);
    const max = Math.max(...highs);
    const padding = (max - min) * 0.15; // 15% padding
    return [min - padding, max + padding];
  }, [visibleData]);

  // Handlers
  const handleBrushChange = (e: any) => {
    if (e.startIndex !== undefined && e.endIndex !== undefined) {
      setViewState({ start: e.startIndex, end: e.endIndex });
    }
  };

  const getPriceFromY = (chartY: number, height: number) => {
    const [min, max] = yDomain;
    if (min === max) return min;
    const top = 10; const bottom = 10; 
    const chartHeight = height - top - bottom;
    if (chartHeight <= 0) return 0;
    const relativeY = chartY - top;
    const ratio = Math.max(0, Math.min(1, relativeY / chartHeight));
    const priceRange = max - min;
    return max - (ratio * priceRange);
  };

  const handleMouseDown = (e: any) => {
    if (!e) return;
    if (tool === 'cursor') { setIsDragging(true); setDragStart(e.chartX); return; }
    if (e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing({ id: Date.now().toString(), type: tool === 'line' ? 'line' : 'box', startX: e.activeLabel, startY: price, endX: e.activeLabel, endY: price });
    }
  };

  const handleMouseMove = (e: any) => {
    if (!e) return;
    if (isDragging && tool === 'cursor' && dragStart !== null && e.chartX) { return; }
    if (currentDrawing && e.activeLabel && typeof e.chartY === 'number') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);
      setCurrentDrawing(prev => ({ ...prev, endX: e.activeLabel, endY: price }));
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false); setDragStart(null);
    if (currentDrawing && currentDrawing.endX && currentDrawing.endY) {
      setDrawings(prev => [...prev, currentDrawing as Drawing]);
      setCurrentDrawing(null);
    }
  };

  const handleUndo = () => {
    setDrawings(prev => prev.slice(0, -1));
  };

  // Custom Shape for Signal Markers
  const RenderSignalShape = (props: any) => {
    const { cx, cy, payload } = props;
    if (payload.type === 'PATTERN') {
      const isTop = payload.patternName === 'TWZ TOP';
      return (
        <g>
          <text 
            x={cx} 
            y={isTop ? cy - 15 : cy + 20} 
            textAnchor="middle" 
            fill={isTop ? COLOR_DOWN : COLOR_UP} 
            fontSize={9} 
            fontWeight="bold"
            fontFamily="monospace"
          >
            {payload.patternName}
          </text>
          <circle cx={cx} cy={cy} r={3} fill="transparent" stroke={isTop ? COLOR_DOWN : COLOR_UP} strokeWidth={2} />
        </g>
      );
    }
    return null;
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const data = payload[0].payload;
      const isUp = data.close >= data.open;
      return (
        <div className="bg-terminal-panel/95 backdrop-blur border border-terminal-border p-3 rounded shadow-xl text-xs font-mono z-50 min-w-[160px]">
          <div className="flex justify-between items-center mb-2 border-b border-terminal-border pb-1">
             <span className="text-terminal-muted">{label}</span>
             <span className={isUp ? 'text-terminal-up' : 'text-terminal-down'}>
                {data.close.toFixed(2)}
             </span>
          </div>
          <div className="grid grid-cols-2 gap-x-3 gap-y-1">
            <span className="text-terminal-muted">O:</span> <span className="text-right text-terminal-text">{data.open.toFixed(2)}</span>
            <span className="text-terminal-muted">H:</span> <span className="text-right text-terminal-text">{data.high.toFixed(2)}</span>
            <span className="text-terminal-muted">L:</span> <span className="text-right text-terminal-text">{data.low.toFixed(2)}</span>
            <span className="text-terminal-muted">C:</span> <span className="text-right text-terminal-text">{data.close.toFixed(2)}</span>
            <span className="text-terminal-muted">Vol:</span> <span className="text-right text-terminal-text">{data.volume}</span>
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <Card 
      title={`Price Action - ${symbol}`} 
      className="h-full flex flex-col relative group"
      actions={
        <div className="flex items-center space-x-2">
           <div className="flex items-center border border-terminal-border rounded overflow-hidden">
              {[TimeFrame.M1, TimeFrame.M5, TimeFrame.H1].map((tf) => (
                <button key={tf} onClick={() => setTimeframe(tf)} className={`px-2 py-0.5 text-[10px] font-mono transition-colors ${timeframe === tf ? 'bg-terminal-accent text-white font-bold' : 'bg-terminal-panel text-terminal-muted hover:text-terminal-text'}`}>{tf}</button>
              ))}
           </div>
           <button onClick={() => setShowToolbar(!showToolbar)} className={`p-1 rounded transition-colors ${showToolbar ? 'text-terminal-accent bg-terminal-accent/10' : 'text-terminal-muted hover:text-terminal-text'}`} title="Tools"><PenTool size={14} /></button>
           <button onClick={() => setIndicators(prev => ({...prev, signals: !prev.signals}))} className={`p-1 rounded transition-colors ${indicators.signals ? 'text-purple-400 bg-purple-400/10' : 'text-terminal-muted'}`} title="AI Patterns"><Activity size={14} /></button>
        </div>
      }
    >
      <div className="flex flex-col h-full bg-terminal-bg relative select-none">

        {/* Toolbar Overlay */}
        {showToolbar && (
          <div className="absolute left-2 top-2 z-20 flex flex-col gap-1 bg-terminal-panel border border-terminal-border rounded shadow-xl p-1 animate-in slide-in-from-left-2 duration-200">
             <button onClick={() => setTool('cursor')} className={`p-2 rounded ${tool === 'cursor' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><MousePointer2 size={16} /></button>
             <button onClick={() => setTool('line')} className={`p-2 rounded ${tool === 'line' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><Pencil size={16} /></button>
             <button onClick={() => setTool('box')} className={`p-2 rounded ${tool === 'box' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-terminal-bg'}`}><Square size={16} /></button>
             <div className="h-px bg-terminal-border my-1"></div>
             <button onClick={handleUndo} className="p-2 rounded text-terminal-muted hover:text-terminal-text"><Undo2 size={16} /></button>
             <button onClick={() => setDrawings([])} className="p-2 rounded text-red-400 hover:bg-red-500/20"><Trash2 size={16} /></button>
          </div>
        )}

        {/* Current Price Info */}
        <div className="absolute top-4 left-14 z-10 pointer-events-none">
          <div className="flex items-baseline space-x-2">
            <h2 className="text-3xl font-bold text-terminal-text font-mono tracking-tighter">{symbol}</h2>
            {visibleData.length > 0 && (
              <div className={`flex items-center space-x-2 text-sm font-mono ${visibleData[visibleData.length-1].close >= visibleData[visibleData.length-1].open ? 'text-terminal-up' : 'text-terminal-down'}`}>
                 <span className="font-bold">{visibleData[visibleData.length-1].close.toFixed(2)}</span>
              </div>
            )}
          </div>
        </div>

        {/* --- MAIN CHART AREA (85%) --- */}
        <div className="flex-[0.85] min-h-0 relative w-full" ref={chartRef}>
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart 
              data={visibleData} // Render ONLY visible data here
              margin={{ top: 10, right: 50, left: 10, bottom: 0 }}
              onMouseDown={handleMouseDown}
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              style={{ cursor: tool === 'cursor' ? (isDragging ? 'grabbing' : 'grab') : 'crosshair' }}
            >
              <defs>
                <linearGradient id="gridGradient" x1="0" y1="0" x2="0" y2="1">
                   <stop offset="0%" stopColor={GRID_COLOR} stopOpacity={0.1}/>
                   <stop offset="100%" stopColor={GRID_COLOR} stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid stroke={GRID_COLOR} strokeDasharray="3 3" vertical={true} />

              {/* Note: XAxis is hidden here to avoid clutter, shown on Navigator below */}
              <XAxis dataKey="time" hide={true} />

              <YAxis 
                yAxisId="price" 
                domain={yDomain} 
                orientation="right" 
                tick={{ fontSize: 10, fill: AXIS_COLOR, fontFamily: 'JetBrains Mono' }} 
                axisLine={false} 
                tickLine={{ stroke: GRID_COLOR }} 
                tickFormatter={(val) => val.toFixed(2)} 
                width={50} 
              />

              <Tooltip content={<CustomTooltip />} cursor={{ stroke: AXIS_COLOR, strokeWidth: 1, strokeDasharray: '4 4' }} isAnimationActive={false} />

              {/* CANDLESTICKS */}
              {/* 1. Wicks (High to Low) */}
              <Bar dataKey={(d) => [d.low, d.high]} yAxisId="price" barSize={1} isAnimationActive={false}>
                {visibleData.map((entry, index) => (
                  <Cell key={`wick-${index}`} fill={entry.close >= entry.open ? COLOR_UP : COLOR_DOWN} />
                ))}
              </Bar>

              {/* 2. Bodies (Open to Close) */}
              <Bar dataKey={(d) => [Math.min(d.open, d.close), Math.max(d.open, d.close)]} yAxisId="price" barSize={8} isAnimationActive={false}>
                {visibleData.map((entry, index) => (
                  <Cell key={`body-${index}`} fill={entry.close >= entry.open ? COLOR_UP : COLOR_DOWN} />
                ))}
              </Bar>

              {/* INDICATORS */}
              {indicators.sma && <Line yAxisId="price" type="monotone" dataKey="sma20" stroke="#fb923c" strokeWidth={1} dot={false} isAnimationActive={false} />}
              {indicators.ema && <Line yAxisId="price" type="monotone" dataKey="ema" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />}

              {/* PATTERNS & SIGNALS */}
              <Line yAxisId="price" type="monotone" dataKey="sma50" stroke="#3b82f6" strokeWidth={1} dot={false} strokeOpacity={0.4} isAnimationActive={false} />
              <Line yAxisId="price" type="monotone" dataKey="sma200" stroke="#a855f7" strokeWidth={1} dot={false} strokeOpacity={0.4} isAnimationActive={false} />
              <Scatter yAxisId="price" data={signalData} shape={<RenderSignalShape />} isAnimationActive={false} />

              {/* DRAWINGS */}
              {drawings.map((d) => (
                d.type === 'line' 
                  ? <ReferenceLine yAxisId="price" key={d.id} segment={[{ x: d.startX, y: d.startY }, { x: d.endX, y: d.endY }]} stroke="#eab308" strokeWidth={2} />
                  : <ReferenceArea yAxisId="price" key={d.id} x1={d.startX} x2={d.endX} y1={d.startY} y2={d.endY} fill="#eab308" fillOpacity={0.2} stroke="#eab308" />
              ))}
              {currentDrawing && currentDrawing.endX && (
                 currentDrawing.type === 'line'
                 ? <ReferenceLine yAxisId="price" segment={[{ x: currentDrawing.startX!, y: currentDrawing.startY! }, { x: currentDrawing.endX, y: currentDrawing.endY }]} stroke="#eab308" strokeWidth={2} strokeDasharray="3 3" />
                 : <ReferenceArea yAxisId="price" x1={currentDrawing.startX} x2={currentDrawing.endX} y1={currentDrawing.startY} y2={currentDrawing.endY} fill="#eab308" fillOpacity={0.1} stroke="#eab308" strokeDasharray="3 3" />
              )}
            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {/* --- NAVIGATOR CHART (15%) --- */}
        <div className="flex-[0.15] w-full border-t border-terminal-border/50 bg-terminal-panel/30">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={fullChartData} margin={{ top: 5, right: 50, left: 10, bottom: 5 }}>
               <defs>
                 <linearGradient id="volumeGradient" x1="0" y1="0" x2="0" y2="1">
                   <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                   <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                 </linearGradient>
               </defs>
               <Area type="monotone" dataKey="close" stroke="#3b82f6" strokeWidth={1} fill="url(#volumeGradient)" isAnimationActive={false} />
               <XAxis 
                  dataKey="time" 
                  tick={{ fontSize: 9, fill: AXIS_COLOR, fontFamily: 'JetBrains Mono' }} 
                  minTickGap={60} 
                  axisLine={false} 
                  tickLine={false} 
                  height={20}
               />
               <Brush 
                  dataKey="time" 
                  height={20} 
                  stroke="#3b82f6" 
                  fill={theme === 'dark' ? '#1a1a1a' : '#f3f4f6'} 
                  fillOpacity={0.5}
                  tickFormatter={() => ''}
                  startIndex={viewState.start}
                  endIndex={viewState.end}
                  onChange={handleBrushChange}
                  alwaysShowText={false}
               />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
    </Card>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  ComposedChart, 
  Bar, 
  Line, 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  ReferenceLine, 
  ReferenceArea, 
  Cell, 
  Scatter, 
  Brush,
  ReferenceDot
} from 'recharts';
import { Card } from './Card';
import { TimeFrame } from '../types';
import { generateChartData } from '../constants';
import { 
  Activity, Pencil, Square, Trash2, MousePointer2, 
  Layers, PenTool, Undo2, ChevronDown, Move, Type,
  TrendingUp, BarChart2
} from 'lucide-react';

interface ChartWidgetProps {
  symbol: string;
  theme?: 'dark' | 'light';
}

type DrawingType = 'line' | 'horizontal' | 'rect';

interface DrawingPoint {
  x: string; // Time label
  y: number; // Price
}

interface Drawing {
  id: string;
  type: DrawingType;
  points: DrawingPoint[]; // Line=2, Rect=2, Horizontal=1
  color: string;
}

type ToolType = 'cursor' | 'line' | 'horizontal' | 'rect';
type ChartType = 'candle' | 'line' | 'area';

// --- Indicators Logic ---
const calculateSMA = (data: any[], period: number) => {
  return data.map((item, index, arr) => {
    if (index < period - 1) return { ...item, [`sma${period}`]: null };
    const slice = arr.slice(index - period + 1, index + 1);
    const sum = slice.reduce((acc, curr) => acc + curr.close, 0);
    return { ...item, [`sma${period}`]: sum / period };
  });
};

const calculateEMA = (data: any[], period: number) => {
  const k = 2 / (period + 1);
  let ema = data[0].close;
  return data.map((item, index) => {
    if (index === 0) return { ...item, ema: item.close };
    ema = (item.close - ema) * k + ema;
    return { ...item, ema };
  });
};

const calculateRSI = (data: any[], period: number = 14) => {
  let gains = 0;
  let losses = 0;

  // Calculate initial average
  for (let i = 1; i <= period; i++) {
    const change = data[i].close - data[i - 1].close;
    if (change > 0) gains += change;
    else losses -= change;
  }

  let avgGain = gains / period;
  let avgLoss = losses / period;

  return data.map((item, index) => {
    if (index <= period) return { ...item, rsi: null };

    const change = item.close - data[index - 1].close;
    const currentGain = change > 0 ? change : 0;
    const currentLoss = change < 0 ? -change : 0;

    avgGain = (avgGain * (period - 1) + currentGain) / period;
    avgLoss = (avgLoss * (period - 1) + currentLoss) / period;

    const rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    const rsi = 100 - (100 / (1 + rs));

    return { ...item, rsi };
  });
};

const calculateMACD = (data: any[]) => {
  // 1. EMA 12
  const k12 = 2 / (12 + 1);
  let ema12 = data[0].close;
  const dataWithEma12 = data.map((item, i) => {
    if(i===0) return { ...item, ema12 };
    ema12 = (item.close - ema12) * k12 + ema12;
    return { ...item, ema12 };
  });

  // 2. EMA 26
  const k26 = 2 / (26 + 1);
  let ema26 = data[0].close;
  const dataWithEma26 = dataWithEma12.map((item, i) => {
    if(i===0) return { ...item, ema26 };
    ema26 = (item.close - ema26) * k26 + ema26;
    return { ...item, ema26 };
  });

  // 3. MACD Line
  const dataWithMacd = dataWithEma26.map(item => ({
    ...item,
    macdLine: item.ema12 - item.ema26
  }));

  // 4. Signal Line (EMA 9 of MACD Line)
  const k9 = 2 / (9 + 1);
  let signal = 0; 
  // Need to skip first 26 to stabilize
  return dataWithMacd.map((item, i) => {
    if (i < 26) return { ...item, macdSignal: null, macdHist: null };
    if (i === 26) { signal = item.macdLine; return { ...item, macdSignal: signal, macdHist: 0 }; }
    signal = (item.macdLine - signal) * k9 + signal;
    return { ...item, macdSignal: signal, macdHist: item.macdLine - signal };
  });
};

export const ChartWidget: React.FC<ChartWidgetProps> = ({ symbol, theme = 'dark' }) => {
  // --- STATE ---
  const [rawData, setRawData] = useState<any[]>([]);
  const [timeframe, setTimeframe] = useState<TimeFrame>(TimeFrame.M5);
  const [viewState, setViewState] = useState({ start: 350, end: 499 });

  // Settings
  const [chartType, setChartType] = useState<ChartType>('candle');
  const [indicators, setIndicators] = useState({ sma: false, ema: false, rsi: false, macd: false });
  const [showToolbar, setShowToolbar] = useState(false);

  // Drawing & Tools
  const [tool, setTool] = useState<ToolType>('cursor');
  const [drawings, setDrawings] = useState<Drawing[]>([]);
  const [activeDrawing, setActiveDrawing] = useState<Partial<Drawing> | null>(null);

  // Dragging logic
  const [dragState, setDragState] = useState<{ 
    isDragging: boolean; 
    drawingId: string | null; 
    pointIndex: number | null; 
  }>({ isDragging: false, drawingId: null, pointIndex: null });

  const chartRef = useRef<HTMLDivElement>(null);

  // --- COLORS ---
  const AXIS_COLOR = theme === 'dark' ? '#555' : '#9ca3af';
  const GRID_COLOR = theme === 'dark' ? '#1a1a1a' : '#e5e7eb';
  const COLOR_UP = '#10b981';
  const COLOR_DOWN = '#ef4444';
  const TOOL_COLOR = '#eab308'; // Yellow

  // --- INITIALIZATION ---
  useEffect(() => {
    const totalPoints = 500;
    const newData = generateChartData(totalPoints);
    setRawData(newData);
    setViewState({ start: totalPoints - 100, end: totalPoints - 1 });
    setDrawings([]);
  }, [symbol, timeframe]);

  // --- DATA PROCESSING ---
  const fullChartData = useMemo(() => {
    if (!rawData.length) return [];
    let processed = [...rawData];
    processed = calculateSMA(processed, 50);
    processed = calculateSMA(processed, 200);
    if (indicators.sma) processed = calculateSMA(processed, 20);
    if (indicators.ema) processed = calculateEMA(processed, 20);
    if (indicators.rsi) processed = calculateRSI(processed);
    if (indicators.macd) processed = calculateMACD(processed);
    return processed;
  }, [rawData, indicators]);

  const visibleData = useMemo(() => {
    if (!fullChartData.length) return [];
    const start = Math.max(0, viewState.start);
    const end = Math.min(fullChartData.length - 1, viewState.end);
    return fullChartData.slice(start, end + 1);
  }, [fullChartData, viewState]);

  const yDomain = useMemo(() => {
    if (!visibleData.length) return [0, 0];
    const highs = visibleData.map(d => d.high);
    const lows = visibleData.map(d => d.low);
    const min = Math.min(...lows);
    const max = Math.max(...highs);
    const padding = (max - min) * 0.15;
    return [min - padding, max + padding];
  }, [visibleData]);

  // --- DRAWING HELPERS ---
  const getPriceFromY = (chartY: number, height: number) => {
    const [min, max] = yDomain;
    if (min === max) return min;
    const top = 10; const bottom = 10; 
    const chartHeight = height - top - bottom;
    if (chartHeight <= 0) return 0;
    const relativeY = chartY - top;
    const ratio = Math.max(0, Math.min(1, relativeY / chartHeight));
    const priceRange = max - min;
    return max - (ratio * priceRange);
  };

  const addPattern = (pattern: string) => {
    if (!visibleData.length) return;

    // Calculate center of view for placing templates
    const centerIndex = Math.floor(visibleData.length / 2);
    const centerTime = visibleData[centerIndex].time;
    const centerPrice = visibleData[centerIndex].close;
    const spreadX = Math.floor(visibleData.length / 6);
    const leftTime = visibleData[Math.max(0, centerIndex - spreadX)].time;
    const rightTime = visibleData[Math.min(visibleData.length-1, centerIndex + spreadX)].time;
    const priceOffset = centerPrice * 0.005;

    const newDrawings: Drawing[] = [];
    const baseId = Date.now().toString();

    switch(pattern) {
      case 'Trendline':
        newDrawings.push({ id: baseId, type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice - priceOffset}, {x: rightTime, y: centerPrice + priceOffset}] });
        break;
      case 'Horizontal':
        newDrawings.push({ id: baseId, type: 'horizontal', color: TOOL_COLOR, points: [{x: centerTime, y: centerPrice}] });
        break;
      case 'Rectangle':
        newDrawings.push({ id: baseId, type: 'rect', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice + priceOffset}, {x: rightTime, y: centerPrice - priceOffset}] });
        break;
      case 'Ascending Triangle':
        newDrawings.push({ id: baseId + '_1', type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice + priceOffset}, {x: rightTime, y: centerPrice + priceOffset}] }); // Top Flat
        newDrawings.push({ id: baseId + '_2', type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice - priceOffset}, {x: rightTime, y: centerPrice + priceOffset}] }); // Bottom Rising
        break;
      case 'Descending Triangle':
        newDrawings.push({ id: baseId + '_1', type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice - priceOffset}, {x: rightTime, y: centerPrice - priceOffset}] }); // Bottom Flat
        newDrawings.push({ id: baseId + '_2', type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice + priceOffset}, {x: rightTime, y: centerPrice - priceOffset}] }); // Top Falling
        break;
      case 'Channel':
        newDrawings.push({ id: baseId + '_1', type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice - priceOffset}, {x: rightTime, y: centerPrice + priceOffset - priceOffset}] }); 
        newDrawings.push({ id: baseId + '_2', type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice + priceOffset}, {x: rightTime, y: centerPrice + priceOffset + priceOffset}] });
        break;
      case 'Head & Shoulders':
         // Simplified as a neckline and two boundaries
         newDrawings.push({ id: baseId + '_neck', type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice - priceOffset}, {x: rightTime, y: centerPrice - priceOffset}] }); 
         newDrawings.push({ id: baseId + '_L', type: 'line', color: TOOL_COLOR, points: [{x: leftTime, y: centerPrice - priceOffset}, {x: visibleData[centerIndex - Math.floor(spreadX/2)].time, y: centerPrice + priceOffset}] });
         newDrawings.push({ id: baseId + '_R', type: 'line', color: TOOL_COLOR, points: [{x: visibleData[centerIndex + Math.floor(spreadX/2)].time, y: centerPrice + priceOffset}, {x: rightTime, y: centerPrice - priceOffset}] });
         break;
    }

    setDrawings(prev => [...prev, ...newDrawings]);
    setTool('cursor'); // Switch to cursor to allow editing
  };

  // --- MOUSE HANDLERS ---
  const handleMouseDown = (e: any) => {
    if (!e || !e.activeLabel) return;

    // 1. Check if clicking a handle (Edit Mode)
    // We check this via the onMouseDown of the Scatter point itself, but if we missed it (click near), we might handle here.
    // However, Recharts makes it easier to attach events to the rendered shape. 
    // See `RenderHandles` component below.

    // 2. Create New Drawing
    if (tool !== 'cursor') {
      const chartHeight = chartRef.current?.clientHeight || 400;
      const price = getPriceFromY(e.chartY, chartHeight);

      const newId = Date.now().toString();
      const points = [{ x: e.activeLabel, y: price }];
      // For horizontal, we only need 1 point initially, others need 2
      if (tool !== 'horizontal') points.push({ x: e.activeLabel, y: price });

      setActiveDrawing({ id: newId, type: tool === 'horizontal' ? 'horizontal' : tool === 'rect' ? 'rect' : 'line', points, color: TOOL_COLOR });
    }
  };

  const handleMouseMove = (e: any) => {
    if (!e || !e.activeLabel) return;
    const chartHeight = chartRef.current?.clientHeight || 400;
    const price = getPriceFromY(e.chartY, chartHeight);

    // dragging an existing handle
    if (dragState.isDragging && dragState.drawingId && dragState.pointIndex !== null) {
      setDrawings(prev => prev.map(d => {
        if (d.id === dragState.drawingId) {
          const newPoints = [...d.points];
          newPoints[dragState.pointIndex!] = { x: e.activeLabel, y: price };
          return { ...d, points: newPoints };
        }
        return d;
      }));
      return;
    }

    // creating a new drawing
    if (activeDrawing) {
      setActiveDrawing(prev => {
        if (!prev || !prev.points) return null;
        const newPoints = [...prev.points];
        if (prev.type === 'horizontal') {
           newPoints[0] = { x: e.activeLabel, y: price };
        } else {
           newPoints[1] = { x: e.activeLabel, y: price };
        }
        return { ...prev, points: newPoints };
      });
    }
  };

  const handleMouseUp = () => {
    if (activeDrawing) {
      setDrawings(prev => [...prev, activeDrawing as Drawing]);
      setActiveDrawing(null);
      // Reset tool to cursor for convenience after drawing
      setTool('cursor'); 
    }
    setDragState({ isDragging: false, drawingId: null, pointIndex: null });
  };

  // --- RENDERERS ---
  const RenderHandles = () => {
    // Collect all points from all drawings to render draggable handles
    // We need to flatten them
    const handleData: any[] = [];
    drawings.forEach(d => {
      d.points.forEach((p, idx) => {
        handleData.push({ x: p.x, y: p.y, drawingId: d.id, pointIndex: idx });
      });
    });

    return (
      <Scatter 
        yAxisId="price"
        data={handleData} 
        shape={(props: any) => (
          <circle 
            cx={props.cx} 
            cy={props.cy} 
            r={5} 
            fill="white" 
            stroke={TOOL_COLOR} 
            strokeWidth={2} 
            cursor="pointer"
            onMouseDown={(e) => {
              e.stopPropagation();
              setDragState({ isDragging: true, drawingId: props.payload.drawingId, pointIndex: props.payload.pointIndex });
            }}
          />
        )}
        isAnimationActive={false}
      />
    );
  };

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const data = payload[0].payload;
      return (
        <div className="bg-terminal-panel/95 backdrop-blur border border-terminal-border p-2 rounded shadow-xl text-[10px] font-mono z-50 min-w-[140px]">
          <div className="flex justify-between items-center mb-1 border-b border-terminal-border pb-1">
             <span className="text-terminal-muted">{label}</span>
          </div>
          <div className="space-y-0.5">
            <div className="flex justify-between"><span className="text-terminal-muted">O:</span> <span>{data.open?.toFixed(2)}</span></div>
            <div className="flex justify-between"><span className="text-terminal-muted">H:</span> <span>{data.high?.toFixed(2)}</span></div>
            <div className="flex justify-between"><span className="text-terminal-muted">L:</span> <span>{data.low?.toFixed(2)}</span></div>
            <div className="flex justify-between"><span className="text-terminal-muted">C:</span> <span className={data.close >= data.open ? 'text-terminal-up' : 'text-terminal-down'}>{data.close?.toFixed(2)}</span></div>
            {indicators.rsi && <div className="flex justify-between text-purple-400"><span className="opacity-70">RSI:</span> <span>{data.rsi?.toFixed(1)}</span></div>}
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <Card 
      title={`Price Action - ${symbol}`} 
      className="h-full flex flex-col relative group"
      actions={
        <div className="flex items-center space-x-2">
           {/* TIMEFRAMES */}
           <div className="flex items-center border border-terminal-border rounded overflow-hidden">
              {[TimeFrame.M1, TimeFrame.M5, TimeFrame.H1].map((tf) => (
                <button key={tf} onClick={() => setTimeframe(tf)} className={`px-2 py-0.5 text-[10px] font-mono transition-colors ${timeframe === tf ? 'bg-terminal-accent text-white font-bold' : 'bg-terminal-panel text-terminal-muted hover:text-terminal-text'}`}>{tf}</button>
              ))}
           </div>

           <div className="h-4 w-px bg-terminal-border"></div>

           {/* CHART TYPES */}
           <div className="flex items-center gap-1">
             <button onClick={() => setChartType('candle')} className={`p-1 rounded ${chartType === 'candle' ? 'text-terminal-accent bg-terminal-accent/10' : 'text-terminal-muted'}`} title="Candles"><BarChart2 size={14} /></button>
             <button onClick={() => setChartType('line')} className={`p-1 rounded ${chartType === 'line' ? 'text-terminal-accent bg-terminal-accent/10' : 'text-terminal-muted'}`} title="Line"><TrendingUp size={14} /></button>
             <button onClick={() => setChartType('area')} className={`p-1 rounded ${chartType === 'area' ? 'text-terminal-accent bg-terminal-accent/10' : 'text-terminal-muted'}`} title="Area"><Activity size={14} /></button>
           </div>

           <div className="h-4 w-px bg-terminal-border"></div>

           {/* INDICATORS TOGGLE */}
           <div className="flex items-center gap-1">
             {(['sma', 'ema', 'macd', 'rsi'] as const).map(ind => (
               <button 
                key={ind}
                onClick={() => setIndicators(prev => ({...prev, [ind]: !prev[ind]}))}
                className={`text-[9px] uppercase px-1.5 py-0.5 rounded border transition-colors ${indicators[ind] ? 'bg-terminal-accent/20 border-terminal-accent text-terminal-accent' : 'border-transparent text-terminal-muted hover:bg-terminal-border'}`}
               >
                 {ind}
               </button>
             ))}
           </div>

           <div className="h-4 w-px bg-terminal-border"></div>

           {/* TOOLBAR TOGGLE */}
           <button onClick={() => setShowToolbar(!showToolbar)} className={`p-1 rounded transition-colors ${showToolbar ? 'text-terminal-accent bg-terminal-accent/10' : 'text-terminal-muted hover:text-terminal-text'}`} title="Drawing Tools"><PenTool size={14} /></button>
        </div>
      }
    >
      <div className="flex flex-col h-full bg-terminal-bg relative select-none">

        {/* --- DRAWING TOOLBAR --- */}
        {showToolbar && (
          <div className="absolute left-2 top-2 z-20 flex flex-col gap-1 bg-terminal-panel border border-terminal-border rounded shadow-xl p-1 animate-in slide-in-from-left-2 duration-200 w-32">
             <div className="text-[9px] text-terminal-muted uppercase font-bold px-2 py-1">Tools</div>
             <div className="grid grid-cols-4 gap-1">
                <button onClick={() => setTool('cursor')} className={`p-1.5 rounded flex justify-center ${tool === 'cursor' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-black/10'}`} title="Select/Move"><MousePointer2 size={14} /></button>
                <button onClick={() => setTool('line')} className={`p-1.5 rounded flex justify-center ${tool === 'line' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-black/10'}`} title="Trendline"><Pencil size={14} /></button>
                <button onClick={() => setTool('horizontal')} className={`p-1.5 rounded flex justify-center ${tool === 'horizontal' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-black/10'}`} title="Horizontal Level"><Undo2 size={14} className="rotate-90" /></button>
                <button onClick={() => setTool('rect')} className={`p-1.5 rounded flex justify-center ${tool === 'rect' ? 'bg-terminal-accent text-white' : 'text-terminal-muted hover:bg-black/10'}`} title="Rectangle"><Square size={14} /></button>
             </div>

             <div className="h-px bg-terminal-border my-1"></div>
             <div className="text-[9px] text-terminal-muted uppercase font-bold px-2 py-1">Patterns</div>

             <div className="flex flex-col gap-0.5 max-h-40 overflow-y-auto">
               {['Ascending Triangle', 'Descending Triangle', 'Channel', 'Head & Shoulders', 'Trendline'].map(p => (
                 <button key={p} onClick={() => addPattern(p)} className="text-left text-[10px] px-2 py-1 hover:bg-black/5 dark:hover:bg-white/5 rounded text-terminal-text truncate">
                   {p}
                 </button>
               ))}
             </div>

             <div className="h-px bg-terminal-border my-1"></div>
             <button onClick={() => setDrawings([])} className="flex items-center gap-2 text-[10px] text-red-400 hover:bg-red-500/10 p-1.5 rounded">
               <Trash2 size={12} /> Clear All
             </button>
          </div>
        )}

        {/* --- MAIN CHART --- */}
        <div className="flex-[0.7] min-h-0 relative w-full" ref={chartRef}>
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart 
              data={visibleData} 
              margin={{ top: 10, right: 50, left: 10, bottom: 0 }}
              onMouseDown={handleMouseDown}
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              style={{ cursor: tool === 'cursor' ? (dragState.isDragging ? 'grabbing' : 'default') : 'crosshair' }}
            >
              <defs>
                <linearGradient id="areaGradient" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={COLOR_UP} stopOpacity={0.3}/>
                  <stop offset="95%" stopColor={COLOR_UP} stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid stroke={GRID_COLOR} strokeDasharray="3 3" vertical={true} />
              <XAxis dataKey="time" hide={true} />
              <YAxis 
                yAxisId="price" 
                domain={yDomain} 
                orientation="right" 
                tick={{ fontSize: 10, fill: AXIS_COLOR, fontFamily: 'JetBrains Mono' }} 
                axisLine={false} 
                tickLine={{ stroke: GRID_COLOR }} 
                tickFormatter={(val) => val.toFixed(2)} 
                width={50} 
              />
              <Tooltip content={<CustomTooltip />} cursor={{ stroke: AXIS_COLOR, strokeWidth: 1, strokeDasharray: '4 4' }} isAnimationActive={false} />

              {/* DRAWINGS */}
              {drawings.map((d) => {
                 if (d.type === 'line' && d.points.length === 2) {
                   return <ReferenceLine yAxisId="price" key={d.id} segment={[{ x: d.points[0].x, y: d.points[0].y }, { x: d.points[1].x, y: d.points[1].y }]} stroke={d.color} strokeWidth={2} />;
                 }
                 if (d.type === 'horizontal' && d.points.length >= 1) {
                   return <ReferenceLine yAxisId="price" key={d.id} y={d.points[0].y} stroke={d.color} strokeWidth={2} />;
                 }
                 if (d.type === 'rect' && d.points.length === 2) {
                   return <ReferenceArea yAxisId="price" key={d.id} x1={d.points[0].x} x2={d.points[1].x} y1={d.points[0].y} y2={d.points[1].y} fill={d.color} fillOpacity={0.1} stroke={d.color} />;
                 }
                 return null;
              })}

              {/* ACTIVE DRAWING PREVIEW */}
              {activeDrawing && activeDrawing.points && (
                 activeDrawing.type === 'line' && activeDrawing.points.length === 2 ? 
                  <ReferenceLine yAxisId="price" segment={[{ x: activeDrawing.points[0].x, y: activeDrawing.points[0].y }, { x: activeDrawing.points[1].x, y: activeDrawing.points[1].y }]} stroke={TOOL_COLOR} strokeWidth={2} strokeDasharray="3 3" /> :
                 activeDrawing.type === 'rect' && activeDrawing.points.length === 2 ?
                  <ReferenceArea yAxisId="price" x1={activeDrawing.points[0].x} x2={activeDrawing.points[1].x} y1={activeDrawing.points[0].y} y2={activeDrawing.points[1].y} fill={TOOL_COLOR} fillOpacity={0.1} stroke={TOOL_COLOR} strokeDasharray="3 3" /> :
                 activeDrawing.type === 'horizontal' && activeDrawing.points.length >= 1 ?
                  <ReferenceLine yAxisId="price" y={activeDrawing.points[0].y} stroke={TOOL_COLOR} strokeWidth={2} strokeDasharray="3 3" /> : null
              )}

              {/* CHART VISUALIZATION */}
              {chartType === 'candle' && (
                <>
                  <Bar dataKey={(d) => [d.low, d.high]} yAxisId="price" barSize={1} isAnimationActive={false}>
                    {visibleData.map((entry, index) => <Cell key={`wick-${index}`} fill={entry.close >= entry.open ? COLOR_UP : COLOR_DOWN} />)}
                  </Bar>
                  <Bar dataKey={(d) => [Math.min(d.open, d.close), Math.max(d.open, d.close)]} yAxisId="price" barSize={7} isAnimationActive={false}>
                    {visibleData.map((entry, index) => <Cell key={`body-${index}`} fill={entry.close >= entry.open ? COLOR_UP : COLOR_DOWN} />)}
                  </Bar>
                </>
              )}
              {chartType === 'line' && (
                <Line yAxisId="price" type="monotone" dataKey="close" stroke={COLOR_UP} strokeWidth={2} dot={false} isAnimationActive={false} />
              )}
              {chartType === 'area' && (
                <Area yAxisId="price" type="monotone" dataKey="close" stroke={COLOR_UP} fill="url(#areaGradient)" isAnimationActive={false} />
              )}

              {/* OVERLAYS */}
              {indicators.sma && <Line yAxisId="price" type="monotone" dataKey="sma20" stroke="#fb923c" strokeWidth={1} dot={false} isAnimationActive={false} />}
              {indicators.ema && <Line yAxisId="price" type="monotone" dataKey="ema" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />}

              {/* DRAG HANDLES */}
              {tool === 'cursor' && <RenderHandles />}

            </ComposedChart>
          </ResponsiveContainer>
        </div>

        {/* --- INDICATOR SUB-CHARTS --- */}
        {(indicators.macd || indicators.rsi) && (
          <div className="flex-[0.25] flex flex-col min-h-0 border-t border-terminal-border/50">
            {indicators.rsi && (
              <div className="flex-1 min-h-0 relative">
                 <div className="absolute top-0 left-1 text-[9px] text-terminal-muted z-10">RSI (14)</div>
                 <ResponsiveContainer width="100%" height="100%">
                   <ComposedChart data={visibleData} margin={{ top: 5, right: 50, left: 10, bottom: 0 }}>
                     <CartesianGrid stroke={GRID_COLOR} strokeDasharray="3 3" vertical={true} />
                     <YAxis orientation="right" domain={[0, 100]} tick={{ fontSize: 9, fill: AXIS_COLOR }} axisLine={false} tickLine={false} width={50} ticks={[30, 70]} />
                     <Tooltip content={<CustomTooltip />} cursor={{ stroke: AXIS_COLOR, strokeDasharray: '4 4' }} isAnimationActive={false} />
                     <ReferenceLine y={70} stroke={AXIS_COLOR} strokeDasharray="3 3" />
                     <ReferenceLine y={30} stroke={AXIS_COLOR} strokeDasharray="3 3" />
                     <Line type="monotone" dataKey="rsi" stroke="#c084fc" strokeWidth={1} dot={false} isAnimationActive={false} />
                   </ComposedChart>
                 </ResponsiveContainer>
              </div>
            )}
            {indicators.macd && (
              <div className="flex-1 min-h-0 relative border-t border-terminal-border/20">
                 <div className="absolute top-0 left-1 text-[9px] text-terminal-muted z-10">MACD (12, 26, 9)</div>
                 <ResponsiveContainer width="100%" height="100%">
                   <ComposedChart data={visibleData} margin={{ top: 5, right: 50, left: 10, bottom: 0 }}>
                     <CartesianGrid stroke={GRID_COLOR} strokeDasharray="3 3" vertical={true} />
                     <YAxis orientation="right" tick={{ fontSize: 9, fill: AXIS_COLOR }} axisLine={false} tickLine={false} width={50} />
                     <Tooltip content={<CustomTooltip />} cursor={{ stroke: AXIS_COLOR, strokeDasharray: '4 4' }} isAnimationActive={false} />
                     <ReferenceLine y={0} stroke={AXIS_COLOR} />
                     <Bar dataKey="macdHist" fill="#444" isAnimationActive={false}>
                        {visibleData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={(entry as any).macdHist > 0 ? '#22c55e' : '#ef4444'} />
                        ))}
                     </Bar>
                     <Line type="monotone" dataKey="macdSignal" stroke="#f97316" strokeWidth={1} dot={false} isAnimationActive={false} />
                     <Line type="monotone" dataKey="macdLine" stroke="#3b82f6" strokeWidth={1} dot={false} isAnimationActive={false} />
                   </ComposedChart>
                 </ResponsiveContainer>
              </div>
            )}
          </div>
        )}

        {/* --- NAVIGATOR --- */}
        {!indicators.macd && !indicators.rsi && (
          <div className="flex-[0.1] w-full border-t border-terminal-border/50 bg-terminal-panel/30">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={fullChartData} margin={{ top: 0, right: 50, left: 10, bottom: 0 }}>
                <defs>
                   <linearGradient id="volGradient" x1="0" y1="0" x2="0" y2="1">
                     <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                     <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                   </linearGradient>
                </defs>
                <Area type="monotone" dataKey="close" stroke="#3b82f6" strokeWidth={1} fill="url(#volGradient)" isAnimationActive={false} />
                <Brush 
                    dataKey="time" 
                    height={20} 
                    stroke="#3b82f6" 
                    fill={theme === 'dark' ? '#1a1a1a' : '#f3f4f6'} 
                    fillOpacity={0.5}
                    tickFormatter={() => ''}
                    startIndex={viewState.start}
                    endIndex={viewState.end}
                    onChange={(e: any) => {
                      if (e.startIndex !== undefined) setViewState({ start: e.startIndex, end: e.endIndex });
                    }}
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        )}
      </div>
    </Card>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Card } from './Card';
import { Quote } from '../types';
import { portfolioService } from '../services/portfolioService';
import { INITIAL_QUOTES } from '../constants';
import { DollarSign, Hash, CheckCircle2, XCircle, ShieldCheck, Zap, ChevronDown, Search } from 'lucide-react';

interface OrderTicketProps {
  quote: Quote | undefined;
  onSymbolChange?: (symbol: string) => void;
}

export const OrderTicket: React.FC<OrderTicketProps> = ({ quote, onSymbolChange }) => {
  const [side, setSide] = useState<'BUY' | 'SELL'>('BUY');
  const [orderType, setOrderType] = useState<'MARKET' | 'LIMIT' | 'STOP'>('LIMIT');
  const [quantity, setQuantity] = useState<number>(100);
  const [price, setPrice] = useState<string>('');
  const [isPaper, setIsPaper] = useState(true);
  const [statusMsg, setStatusMsg] = useState<{type: 'success'|'error', text: string} | null>(null);

  // Dropdown State
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const searchRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const unsubscribe = portfolioService.subscribeMode(setIsPaper);
    return unsubscribe;
  }, []);

  useEffect(() => {
    if (quote && price === '' && orderType === 'LIMIT') {
      setPrice(quote.price.toFixed(2));
    }
  }, [quote, orderType]);

  useEffect(() => {
    if (statusMsg) {
      const timer = setTimeout(() => setStatusMsg(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [statusMsg]);

  // Handle outside click to close dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!quote) { setStatusMsg({ type: 'error', text: 'No Symbol' }); return; }
    const executionPrice = orderType === 'MARKET' ? quote.price : parseFloat(price);
    if (isNaN(executionPrice) || executionPrice <= 0) { setStatusMsg({ type: 'error', text: 'Invalid Price' }); return; }
    if (quantity <= 0) { setStatusMsg({ type: 'error', text: 'Invalid Qty' }); return; }
    const result = portfolioService.executeTrade(quote.symbol, side, quantity, executionPrice);
    if (result.success) { setStatusMsg({ type: 'success', text: result.message }); } 
    else { setStatusMsg({ type: 'error', text: result.message }); }
  };

  const filteredQuotes = INITIAL_QUOTES.filter(q => 
    q.symbol.toLowerCase().includes(searchTerm.toLowerCase()) || 
    q.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const total = quote ? (quantity * (orderType === 'MARKET' ? quote.price : parseFloat(price) || 0)).toFixed(2) : '0.00';

  return (
    <Card title="Order Entry" className="h-full flex flex-col overflow-visible">
      <div className="p-2 space-y-2 font-mono text-sm flex-1 relative">

        {/* Symbol Selection Header */}
        <div className="relative border-b border-terminal-border pb-2 z-20" ref={searchRef}>
           <div className="flex justify-between items-start">
              <div 
                className="flex flex-col cursor-pointer group select-none"
                onClick={() => {
                  setSearchTerm('');
                  setIsDropdownOpen(!isDropdownOpen);
                }}
              >
                <div className="flex items-center gap-1">
                  <span className="text-xl font-bold text-terminal-accent group-hover:text-white transition-colors">
                     {quote?.symbol || 'SELECT'}
                  </span>
                  <ChevronDown size={14} className={`text-terminal-muted transition-transform duration-200 ${isDropdownOpen ? 'rotate-180' : ''}`} />
                </div>
                <span className="text-[10px] text-terminal-muted">{quote?.name || 'Choose a ticker'}</span>
              </div>

              <div className="text-right">
                <div className="text-lg font-bold text-terminal-text">{quote?.price.toFixed(2) || '0.00'}</div>
                <div className="text-[9px] flex gap-2 justify-end">
                   <span className="text-terminal-muted">Bid <span className="text-terminal-up">{quote?.bid.toFixed(2) || '--'}</span></span>
                   <span className="text-terminal-muted">Ask <span className="text-terminal-down">{quote?.ask.toFixed(2) || '--'}</span></span>
                </div>
              </div>
           </div>

           {/* Dropdown Menu */}
           {isDropdownOpen && (
             <div className="absolute top-full left-0 w-full mt-1 bg-terminal-panel border border-terminal-border shadow-2xl rounded-sm overflow-hidden flex flex-col max-h-64 animate-in fade-in zoom-in-95 duration-100 origin-top-left z-50">
               <div className="p-2 border-b border-terminal-border flex items-center gap-2 bg-terminal-bg">
                 <Search size={12} className="text-terminal-muted" />
                 <input 
                   autoFocus
                   type="text" 
                   className="w-full bg-transparent text-xs text-terminal-text focus:outline-none placeholder-terminal-muted font-mono uppercase"
                   placeholder="SEARCH SYMBOL..."
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                   onClick={(e) => e.stopPropagation()}
                 />
               </div>
               <div className="overflow-y-auto flex-1 scrollbar-thin">
                 {filteredQuotes.map(q => (
                   <button 
                     key={q.symbol}
                     className="w-full px-3 py-2 hover:bg-terminal-accent/10 hover:text-terminal-accent flex justify-between items-center text-xs border-b border-terminal-border/30 last:border-0 transition-colors text-left"
                     onClick={() => {
                       if (onSymbolChange) {
                          onSymbolChange(q.symbol);
                          // Reset price if in Limit mode to new price
                          if (orderType === 'LIMIT') setPrice(q.price.toFixed(2));
                       }
                       setIsDropdownOpen(false);
                     }}
                   >
                     <div className="flex flex-col">
                        <span className="font-bold font-mono">{q.symbol}</span>
                        <span className="text-[9px] text-terminal-muted uppercase truncate max-w-[120px]">{q.name}</span>
                     </div>
                     <span className={`font-mono ${q.change >= 0 ? 'text-terminal-up' : 'text-terminal-down'}`}>{q.price.toFixed(2)}</span>
                   </button>
                 ))}
                 {filteredQuotes.length === 0 && (
                   <div className="p-4 text-center text-[10px] text-terminal-muted">No symbols found.</div>
                 )}
               </div>
             </div>
           )}
        </div>

        {/* Side Selection */}
        <div className="flex rounded bg-terminal-bg border border-terminal-border p-0.5">
          <button onClick={() => setSide('BUY')} className={`flex-1 py-1 text-center font-bold rounded text-[10px] uppercase transition-all ${side === 'BUY' ? 'bg-terminal-up text-black' : 'text-terminal-muted hover:text-terminal-text'}`}>Buy</button>
          <button onClick={() => setSide('SELL')} className={`flex-1 py-1 text-center font-bold rounded text-[10px] uppercase transition-all ${side === 'SELL' ? 'bg-terminal-down text-white' : 'text-terminal-muted hover:text-terminal-text'}`}>Sell</button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-2 mt-2">
          {/* Order Type */}
          <div className="grid grid-cols-3 gap-1">
             {['MARKET', 'LIMIT', 'STOP'].map((t) => (
               <button key={t} type="button" onClick={() => setOrderType(t as any)} className={`py-1 text-[9px] border border-terminal-border rounded uppercase transition-colors ${orderType === t ? 'bg-terminal-accent/10 text-terminal-accent border-terminal-accent font-bold' : 'text-terminal-muted hover:border-terminal-muted hover:text-terminal-text'}`}>{t}</button>
             ))}
          </div>

          <div className="flex gap-2">
            {/* Quantity */}
            <div className="flex-1 space-y-0.5">
              <label className="text-[9px] text-terminal-muted uppercase flex items-center gap-1"><Hash size={8} /> Qty</label>
              <input type="number" value={quantity} onChange={(e) => setQuantity(Number(e.target.value))} className="w-full bg-terminal-bg border border-terminal-border p-1.5 text-right text-terminal-text text-xs focus:border-terminal-accent focus:outline-none font-mono rounded-sm transition-colors" />
            </div>

            {/* Price (Conditional) */}
            <div className="flex-1 space-y-0.5">
               {orderType !== 'MARKET' ? (
                <>
                  <label className="text-[9px] text-terminal-muted uppercase flex items-center gap-1"><DollarSign size={8} /> Price</label>
                  <input type="number" step="0.01" value={price} onChange={(e) => setPrice(e.target.value)} className="w-full bg-terminal-bg border border-terminal-border p-1.5 text-right text-terminal-text text-xs focus:border-terminal-accent focus:outline-none font-mono rounded-sm transition-colors" />
                </>
               ) : (
                <>
                  <label className="text-[9px] text-terminal-muted uppercase flex items-center gap-1">Est Price</label>
                  <div className="w-full bg-black/5 dark:bg-white/5 border border-transparent p-1.5 text-right text-terminal-muted text-xs font-mono rounded-sm">{quote?.price.toFixed(2) || '0.00'}</div>
                </>
               )}
            </div>
          </div>

          {/* Submit Button */}
          <button type="submit" className={`w-full py-2 font-bold text-xs uppercase tracking-wider rounded shadow active:scale-[0.98] transition-all mt-2 ${side === 'BUY' ? 'bg-terminal-up text-black hover:brightness-110' : 'bg-terminal-down text-white hover:brightness-110'}`}>
            {side} {quote?.symbol || 'STOCK'} <span className="opacity-70 ml-1">(${total})</span>
          </button>
        </form>

        {/* Status Messages */}
        {statusMsg && (
          <div className={`p-1.5 rounded text-[10px] flex items-center gap-2 animate-in fade-in slide-in-from-top-1 ${statusMsg.type === 'success' ? 'bg-green-500/10 text-green-600 dark:text-green-400 border border-green-500/20' : 'bg-red-500/10 text-red-600 dark:text-red-400 border border-red-500/20'}`}>
            {statusMsg.type === 'success' ? <CheckCircle2 size={12} /> : <XCircle size={12} />}
            <span className="truncate font-medium">{statusMsg.text}</span>
          </div>
        )}
      </div>

      {/* Footer / Status */}
      <div className={`px-2 py-1 border-t text-[9px] flex items-center justify-between font-bold ${
        isPaper 
          ? 'bg-yellow-500/5 text-yellow-600 dark:text-yellow-500 border-yellow-500/20' 
          : 'bg-green-500/5 text-green-600 dark:text-green-500 border-green-500/20'
      }`}>
        <div className="flex items-center gap-1">
           {isPaper ? <ShieldCheck size={10} /> : <Zap size={10} />}
           <span>{isPaper ? 'PAPER ACCOUNT' : 'LIVE MARKET'}</span>
        </div>
        <div className="opacity-50">
           TIF: GTC
        </div>
      </div>
    </Card>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { QuoteGrid } from './components/QuoteGrid';
import { ChartWidget } from './components/ChartWidget';
import { OrderTicket } from './components/OrderTicket';
import { NewsFeed } from './components/NewsFeed';
import { PredictionWidget } from './components/PredictionWidget';
import { CommandPalette } from './components/CommandPalette';
import { PortfolioWidget } from './components/PortfolioWidget';
import { AIAssistant } from './components/AIAssistant';
import { marketService } from './services/marketService';
import { portfolioService } from './services/portfolioService';
import { Quote } from './types';

function App() {
  const [activeTab, setActiveTab] = useState<'trade' | 'research'>('trade');
  const [selectedSymbol, setSelectedSymbol] = useState<string>('AAPL');
  const [selectedQuote, setSelectedQuote] = useState<Quote | undefined>(undefined);
  const [isCommandOpen, setIsCommandOpen] = useState(false);
  const [isPaper, setIsPaper] = useState(true);
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  // Theme Management
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  // Sync selected quote with real-time updates
  useEffect(() => {
    const unsubscribe = marketService.subscribe((quotes) => {
      const quote = quotes.find(q => q.symbol === selectedSymbol);
      if (quote) {
        setSelectedQuote(quote);
      }
    });
    return unsubscribe;
  }, [selectedSymbol]);

  // Sync portfolio mode
  useEffect(() => {
    const unsubscribe = portfolioService.subscribeMode(setIsPaper);
    return unsubscribe;
  }, []);

  // Global Key Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsCommandOpen(true);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  return (
    <div className="flex flex-col h-screen bg-terminal-bg text-terminal-text font-sans selection:bg-terminal-accent selection:text-black overflow-hidden transition-colors duration-200">

      <Header 
        onOpenCommand={() => setIsCommandOpen(true)} 
        isPaper={isPaper}
        onToggleMode={() => portfolioService.toggleMode()}
        activeTab={activeTab}
        onTabChange={setActiveTab}
        theme={theme}
        onToggleTheme={toggleTheme}
      />

      {/* Main Page Layout */}
      <main className="flex-1 overflow-hidden relative p-1">

        {/* ================= TRADE VIEW ================= */}
        {activeTab === 'trade' && (
          <div className="flex flex-col lg:flex-row h-full w-full gap-1 animate-in fade-in duration-300">

            {/* LEFT COLUMN: Execution & Market Data (25%) */}
            <div className="w-full lg:w-[25%] flex flex-col gap-1 h-full min-w-[300px]">

              {/* Order Ticket (Fixed Height) */}
              <div className="h-auto min-h-[320px] shrink-0 z-20">
                <OrderTicket quote={selectedQuote} onSymbolChange={setSelectedSymbol} />
              </div>

              {/* Quote Grid (Fills remaining) */}
              <div className="flex-1 min-h-0 z-10">
                <QuoteGrid 
                  onSelectSymbol={setSelectedSymbol} 
                  selectedSymbol={selectedSymbol} 
                />
              </div>
            </div>

            {/* RIGHT COLUMN: Charting (75%) */}
            <div className="flex-1 h-full min-w-0 z-0">
              <ChartWidget symbol={selectedSymbol} theme={theme} />
            </div>

          </div>
        )}

        {/* ================= RESEARCH VIEW ================= */}
        {activeTab === 'research' && (
          <div className="flex flex-col lg:flex-row h-full w-full gap-1 animate-in fade-in duration-300">

            {/* LEFT COLUMN: Portfolio & Holdings (30%) */}
            <div className="w-full lg:w-[30%] h-full min-h-0">
               <PortfolioWidget />
            </div>

            {/* CENTER COLUMN: AI Assistant (40%) */}
            <div className="w-full lg:w-[40%] h-full min-h-0">
              <AIAssistant theme={theme} />
            </div>

            {/* RIGHT COLUMN: Analysis Tools (30%) */}
            <div className="w-full lg:w-[30%] h-full flex flex-col gap-1 min-h-0">

              {/* Top: AI Prediction */}
              <div className="flex-1 min-h-0">
                <PredictionWidget symbol={selectedSymbol} theme={theme} />
              </div>

              {/* Bottom: News Feed */}
              <div className="flex-1 min-h-0">
                <NewsFeed />
              </div>

            </div>
          </div>
        )}

      </main>

      {/* Command Palette Modal */}
      <CommandPalette 
        isOpen={isCommandOpen} 
        onClose={() => setIsCommandOpen(false)}
        onSelect={setSelectedSymbol}
      />
    </div>
  );
}

export default App;
